function getLocale() {
  return LOCALE_BY_LANG[state.lang] || "uk-UA";
}

function isLikelyMojibake(value) {
  if (typeof value !== "string" || !value) {
    return false;
  }

  const suspiciousTokens = /(?:\u0420\u00A0\u0412\u00A0|\u0420\u2019|\u0420\u040B|\u0420\u2039|\u0420\u2020|\u0420\u201A|\u0420\u0406\u0420\u201A|\u0403|\u2122|\u0412\u00A0|\u0432\u20AC)/g;
  const matches = value.match(suspiciousTokens);

  if (!matches) {
    return false;
  }

  const density = matches.length / Math.max(value.length, 1);
  return matches.length >= 3 && density >= 0.04;
}

function isLikelyQuestionCorruption(value) {
  if (typeof value !== "string" || value.length < 4) {
    return false;
  }

  const questionCount = (value.match(/\?/g) || []).length;
  if (questionCount === 0) {
    return false;
  }

  const density = questionCount / value.length;
  return questionCount >= 4 && density >= 0.2;
}

function getCleanTranslation(key) {
  const primary = I18N[state.lang] || {};
  const uk = I18N.uk || {};
  const en = I18N.en || {};

  const candidates =
    state.lang === "uk"
      ? [primary[key], en[key], uk[key]]
      : [primary[key], uk[key], en[key]];

  for (const candidate of candidates) {
    if (typeof candidate === "string" && candidate && !isLikelyMojibake(candidate) && !isLikelyQuestionCorruption(candidate)) {
      return candidate;
    }
  }

  if (typeof en[key] === "string" && en[key]) {
    return en[key];
  }

  if (typeof uk[key] === "string" && uk[key] && !isLikelyMojibake(uk[key]) && !isLikelyQuestionCorruption(uk[key])) {
    return uk[key];
  }

  return key;
}

function t(key, params = {}) {
  const template = getCleanTranslation(key);

  return template.replace(/\{(\w+)\}/g, (_match, token) => {
    return params[token] !== undefined ? String(params[token]) : `{${token}}`;
  });
}
function localizeApiError(messageInput) {
  const message = String(messageInput || "").trim();
  const key = API_ERROR_KEY_BY_MESSAGE[message];

  if (!key) {
    return message || t("common.noData");
  }

  return t(key);
}

function toFiniteNumber(input, fallback = 0) {
  const numeric = Number(input);
  return Number.isFinite(numeric) ? numeric : fallback;
}

function normalizeAuthUser(input) {
  if (!input || typeof input !== "object") {
    return null;
  }

  const walletInput = input.wallet && typeof input.wallet === "object" ? input.wallet : {};
  const portfolioInput = Array.isArray(input.portfolio) ? input.portfolio : [];
  const user = {
    id: String(input.id || ""),
    email: String(input.email || ""),
    displayName: normalizeDisplayNameInput(input.displayName || ""),
    avatarUrl: typeof input.avatarUrl === "string" && input.avatarUrl.trim() ? input.avatarUrl.trim() : null,
    isOwner: Boolean(input.isOwner),
    wallet: {
      usd: toFiniteNumber(walletInput.usd, 0),
      btc: toFiniteNumber(walletInput.btc, 0),
      eth: toFiniteNumber(walletInput.eth, 0)
    },
    portfolio: portfolioInput
      .map((item) => {
        if (!item || typeof item !== "object") {
          return null;
        }

        const normalized = {
          symbol: String(item.symbol || "").trim().toUpperCase(),
          assetCode: String(item.assetCode || "").trim().toUpperCase(),
          amount: toFiniteNumber(item.amount, 0),
          investedUsd: toFiniteNumber(item.investedUsd, 0),
          averageBuyPriceUsd: toFiniteNumber(item.averageBuyPriceUsd, 0),
          lastBuyAt: String(item.lastBuyAt || "")
        };

        return normalized.symbol && normalized.assetCode && normalized.amount > 0 ? normalized : null;
      })
      .filter(Boolean),
    isBanned: Boolean(input.isBanned),
    banReason: typeof input.banReason === "string" ? input.banReason : null,
    bannedAt: typeof input.bannedAt === "string" ? input.bannedAt : null,
    createdAt: String(input.createdAt || new Date().toISOString())
  };

  if (!user.id || !user.email) {
    return null;
  }

  if (!user.displayName) {
    user.displayName = user.email.split("@")[0] || "User";
  }

  return user;
}

function getDisplayInitials(value) {
  const words = String(value || "")
    .trim()
    .split(/\s+/)
    .filter(Boolean);

  if (!words.length) {
    return "U";
  }

  if (words.length === 1) {
    return words[0].slice(0, 1).toUpperCase();
  }

  return `${words[0].slice(0, 1)}${words[1].slice(0, 1)}`.toUpperCase();
}

function buildDefaultAvatarDataUrl(name) {
  const initials = encodeURIComponent(getDisplayInitials(name));
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="128" height="128" viewBox="0 0 128 128"><defs><linearGradient id="g" x1="0" y1="0" x2="1" y2="1"><stop stop-color="#58a6ff" offset="0%"/><stop stop-color="#33d69f" offset="100%"/></linearGradient></defs><rect width="128" height="128" rx="64" fill="url(#g)"/><text x="64" y="74" text-anchor="middle" font-family="Space Grotesk, Segoe UI, sans-serif" font-size="46" fill="#06274c" font-weight="700">${initials}</text></svg>`;
  return `data:image/svg+xml;charset=UTF-8,${encodeURIComponent(svg)}`;
}

function getUserAvatarUrl(user) {
  if (user?.avatarUrl) {
    return user.avatarUrl;
  }

  return buildDefaultAvatarDataUrl(user?.displayName || user?.email || "User");
}

function normalizeDisplayNameInput(value) {
  return String(value || "").trim().normalize("NFC");
}

function validateDisplayNameInput(value) {
  return /^[\p{L}\p{N} _.-]{2,40}$/u.test(String(value || "").trim());
}

function validateEmailInput(value) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(String(value || "").trim());
}

const TOPUP_CARD_DIGIT_LENGTH = 16;

function normalizeCardDigits(value, maxLength = TOPUP_CARD_DIGIT_LENGTH) {
  return String(value || "")
    .replace(/\D+/g, "")
    .slice(0, maxLength);
}

function formatCardNumberInputValue(value) {
  const digits = normalizeCardDigits(value, TOPUP_CARD_DIGIT_LENGTH);
  return digits.replace(/(.{4})/g, "$1 ").trim();
}

function getTopupCardBrand(digits) {
  const value = String(digits || "");

  if (/^4\d{15}$/.test(value)) {
    return "visa";
  }

  const prefix2 = Number(value.slice(0, 2));
  const prefix4 = Number(value.slice(0, 4));

  if ((prefix2 >= 51 && prefix2 <= 55) || (prefix4 >= 2221 && prefix4 <= 2720)) {
    return "mastercard";
  }

  return "";
}

function isLuhnValid(digits) {
  const value = String(digits || "");
  let sum = 0;
  let shouldDouble = false;

  for (let index = value.length - 1; index >= 0; index -= 1) {
    let digit = value.charCodeAt(index) - 48;

    if (digit < 0 || digit > 9) {
      return false;
    }

    if (shouldDouble) {
      digit *= 2;

      if (digit > 9) {
        digit -= 9;
      }
    }

    sum += digit;
    shouldDouble = !shouldDouble;
  }

  return sum > 0 && sum % 10 === 0;
}

function normalizeCardHolderInput(value) {
  return String(value || "")
    .replace(/[^\p{L}\s.'вҖҷ-]+/gu, "")
    .replace(/\s+/g, " ")
    .slice(0, 64);
}

function hasOnlyAllowedCardNumberChars(value) {
  return !/[^0-9\s]/.test(String(value || ""));
}

function hasOnlyAllowedCardHolderChars(value) {
  return !/[^\p{L}\s.'вҖҷ-]/u.test(String(value || ""));
}

function hasOnlyAllowedExpiryChars(value) {
  return !/[^0-9/\s]/.test(String(value || ""));
}

function hasOnlyAllowedCvvChars(value) {
  return !/[^0-9]/.test(String(value || ""));
}

function hasOnlyAllowedMoneyChars(value) {
  return !/[^0-9.,\s]/.test(String(value || ""));
}

function hasSingleDecimalSeparator(value) {
  const separators = (String(value || "").match(/[.,]/g) || []).length;
  return separators <= 1;
}

function setFieldInvalidChars(field, hasInvalidChars) {
  if (!field) {
    return;
  }

  field.dataset.invalidChars = hasInvalidChars ? "true" : "false";
}

function hasFieldInvalidChars(field) {
  return field?.dataset.invalidChars === "true";
}

function formatMoneyInputValue(value, maxIntegerDigits = 9, maxFractionDigits = 2) {
  const raw = String(value || "").replace(/\s+/g, "").replace(/,/g, ".");
  const cleaned = raw.replace(/[^0-9.]/g, "");
  const firstDotIndex = cleaned.indexOf(".");
  const integerRaw = firstDotIndex >= 0 ? cleaned.slice(0, firstDotIndex) : cleaned;
  const fractionRaw = firstDotIndex >= 0 ? cleaned.slice(firstDotIndex + 1).replace(/\./g, "") : "";
  const integerPart = integerRaw.replace(/^0+(?=\d)/, "").slice(0, maxIntegerDigits);
  const fractionPart = fractionRaw.slice(0, maxFractionDigits);
  const hadTrailingSeparator = firstDotIndex >= 0 && cleaned.endsWith(".") && !fractionPart;

  if (firstDotIndex >= 0) {
    if (fractionPart) {
      return `${integerPart || "0"}.${fractionPart}`;
    }

    if (hadTrailingSeparator) {
      return `${integerPart || "0"}.`;
    }
  }

  return integerPart;
}

function parseDecimalInput(value) {
  const normalized = String(value || "").replace(/\s+/g, "").replace(/,/g, ".");
  const numeric = Number(normalized);
  return Number.isFinite(numeric) ? numeric : Number.NaN;
}

function formatCardExpiryInputValue(value) {
  const digits = normalizeCardDigits(value, 4);

  if (digits.length <= 2) {
    return digits;
  }

  return `${digits.slice(0, 2)}/${digits.slice(2)}`;
}

function formatCardCvvInputValue(value) {
  return normalizeCardDigits(value, 3);
}

function validateTopupCardNumberInput(value) {
  const digits = normalizeCardDigits(value, TOPUP_CARD_DIGIT_LENGTH);
  return (
    digits.length === TOPUP_CARD_DIGIT_LENGTH &&
    !/^0+$/.test(digits) &&
    Boolean(getTopupCardBrand(digits)) &&
    isLuhnValid(digits)
  );
}

function validateTopupCardHolderInput(value) {
  const normalized = normalizeCardHolderInput(value).trim();
  const parts = normalized.split(" ").filter(Boolean);

  return (
    parts.length >= 2 &&
    parts.length <= 4 &&
    parts.every((part) => {
      const lettersOnly = part.replace(/[.'вҖҷ-]/g, "");
      return lettersOnly.length >= 2 && /^[\p{L}][\p{L}.'вҖҷ-]*$/u.test(part);
    })
  );
}

function validateTopupCardExpiryInput(value) {
  const match = /^(\d{2})\/(\d{2})$/.exec(String(value || "").trim());

  if (!match) {
    return false;
  }

  const month = Number(match[1]);
  const year = Number(match[2]);

  if (!Number.isInteger(month) || month < 1 || month > 12) {
    return false;
  }

  const now = new Date();
  const fullYear = 2000 + year;
  const expiresAt = new Date(fullYear, month, 0, 23, 59, 59, 999).getTime();
  return expiresAt >= now.getTime();
}

function validateTopupCardCvvInput(value) {
  return /^\d{3}$/.test(String(value || "").trim());
}

function validatePasswordInput(value) {
  const password = String(value || "");
  return password.length >= 8 && /[A-Za-z]/.test(password) && /\d/.test(password);
}

function normalizeExchangeSourceFilter(input) {
  const value = String(input || "all").trim().toLowerCase();
  return value === "ws" || value === "rest" ? value : "all";
}

function normalizeExchangeSortKey(input) {
  const value = String(input || "exchange_asc").trim().toLowerCase();
  const allowed = new Set([
    "exchange_asc",
    "exchange_desc",
    "updated_desc",
    "updated_asc",
    "volume_desc",
    "spread_desc"
  ]);

  return allowed.has(value) ? value : "exchange_asc";
}

function compareExchangeRows(a, b, sortKeyInput) {
  const sortKey = normalizeExchangeSortKey(sortKeyInput);
  const exchangeNameA = getExchangeInfo(a.exchange).name;
  const exchangeNameB = getExchangeInfo(b.exchange).name;
  const symbolA = String(a.symbol || "");
  const symbolB = String(b.symbol || "");

  const fallback = () => {
    const byExchange = exchangeNameA.localeCompare(exchangeNameB);

    if (byExchange !== 0) {
      return byExchange;
    }

    return symbolA.localeCompare(symbolB);
  };

  switch (sortKey) {
    case "exchange_desc":
      return fallback() * -1;
    case "updated_desc":
      return Number(b.tsIngested || 0) - Number(a.tsIngested || 0) || fallback();
    case "updated_asc":
      return Number(a.tsIngested || 0) - Number(b.tsIngested || 0) || fallback();
    case "volume_desc":
      return Number(b.volume24h || 0) - Number(a.volume24h || 0) || fallback();
    case "spread_desc":
      return toFiniteNumber(b.spread, 0) - toFiniteNumber(a.spread, 0) || fallback();
    case "exchange_asc":
    default:
      return fallback();
  }
}

function attachPasswordToggle(inputElement, buttonElement) {
  if (!inputElement || !buttonElement) {
    return;
  }

  const syncToggleState = () => {
    const revealed = inputElement.type === "text";
    buttonElement.classList.toggle("active", revealed);
    buttonElement.setAttribute("aria-pressed", revealed ? "true" : "false");
  };

  buttonElement.addEventListener("click", () => {
    const reveal = inputElement.type === "password";
    inputElement.type = reveal ? "text" : "password";
    syncToggleState();
  });

  syncToggleState();
}

function formatCryptoAmount(value, assetCode) {
  const numeric = toFiniteNumber(value, Number.NaN);

  if (!Number.isFinite(numeric)) {
    return "-";
  }

  return `${new Intl.NumberFormat(getLocale(), {
    minimumFractionDigits: 2,
    maximumFractionDigits: 6
  }).format(numeric)} ${assetCode}`;
}

function populateLanguageSelect() {
  const flagEmoji = (countryCode) =>
    String(countryCode || "")
      .toUpperCase()
      .replace(/[A-Z]/g, (char) => String.fromCodePoint(127397 + char.charCodeAt(0)));

  const options = [
    ["uk", `${flagEmoji("UA")} UA`],
    ["en", `${flagEmoji("GB")} EN`],
    ["de", `${flagEmoji("DE")} DE`],
    ["fr", `${flagEmoji("FR")} FR`],
    ["it", `${flagEmoji("IT")} IT`],
    ["pt", `${flagEmoji("PT")} PT`],
    ["es", `${flagEmoji("ES")} ES`],
    ["pl", `${flagEmoji("PL")} PL`],
    ["bg", `${flagEmoji("BG")} BG`],
    ["el", `${flagEmoji("GR")} EL`],
    ["tr", `${flagEmoji("TR")} TR`],
    ["ko", `${flagEmoji("KR")} KO`],
    ["ja", `${flagEmoji("JP")} JA`],
    ["ar", `${flagEmoji("SA")} AR`],
    ["zh", `${flagEmoji("CN")} ZH`]
  ];

  refs.languageSelect.innerHTML = options
    .map(([code, label]) => `<option value="${code}">${label}</option>`)
    .join("");

  refs.languageSelect.value = normalizeLanguageCode(state.lang);
  refs.languageSelect.dataset.lang = refs.languageSelect.value;
}

