function applyI18nToDom() {
  refs.root.setAttribute("lang", state.lang);

  document.querySelectorAll("[data-i18n]").forEach((element) => {
    const key = element.getAttribute("data-i18n");

    if (!key) {
      return;
    }

    element.textContent = t(key);
  });

  document.querySelectorAll("[data-i18n-placeholder]").forEach((element) => {
    const key = element.getAttribute("data-i18n-placeholder");

    if (!key) {
      return;
    }

    element.setAttribute("placeholder", t(key));
  });

  document.querySelectorAll("[data-i18n-title]").forEach((element) => {
    const key = element.getAttribute("data-i18n-title");

    if (!key) {
      return;
    }

    element.setAttribute("title", t(key));
  });

  populateLanguageSelect();
  setTheme(refs.root.getAttribute("data-theme") === "light" ? "light" : "dark");
  setWsState(state.ws.status, state.ws.ok);
}

function setLanguage(lang) {
  const next = normalizeLanguageCode(lang);

  if (next === state.lang) {
    return;
  }

  state.lang = next;
  localStorage.setItem(LANG_KEY, next);
  applyI18nToDom();
  renderAll();
}

function setWsState(status, ok) {
  state.ws.status = status;
  state.ws.ok = ok;

  refs.wsBadge.textContent = `WS: ${t(`ws.${status}`)}`;
  refs.wsBadge.classList.remove("ok", "warn");
  refs.wsBadge.classList.add(ok ? "ok" : "warn");
}

function setTheme(theme) {
  const normalized = theme === "light" ? "light" : "dark";
  refs.root.setAttribute("data-theme", normalized);
  localStorage.setItem(THEME_KEY, normalized);
  refs.themeToggle.dataset.theme = normalized;
  refs.themeToggle.textContent = getThemeLabel(normalized);
  refs.themeToggle.setAttribute("aria-label", refs.themeToggle.textContent);
  refs.themeToggle.setAttribute("title", refs.themeToggle.textContent);
}

function initTheme() {
  const saved = localStorage.getItem(THEME_KEY);

  if (saved === "light" || saved === "dark") {
    setTheme(saved);
    return;
  }

  setTheme("light");
}

function switchTab(tabName) {
  refs.menuBtns.forEach((btn) => {
    btn.classList.toggle("active", btn.dataset.tab === tabName);
  });

  refs.panes.forEach((pane) => {
    pane.classList.toggle("active", pane.dataset.pane === tabName);
  });
}

function splitSymbol(symbol) {
  const upper = String(symbol || "").toUpperCase();

  for (const quote of QUOTE_ASSETS) {
    if (upper.endsWith(quote) && upper.length > quote.length) {
      return {
        base: upper.slice(0, upper.length - quote.length),
        quote
      };
    }
  }

  return {
    base: upper,
    quote: ""
  };
}

function getBaseSymbol(symbol) {
  return splitSymbol(symbol).base;
}

function formatSymbolPair(symbol) {
  const { base, quote } = splitSymbol(symbol);
  return quote ? `${base}/${quote}` : base;
}

function getDisplayName(symbol) {
  const base = getBaseSymbol(symbol);
  return SYMBOL_META[base]?.name || base;
}

function getCoinIcon(symbol) {
  const base = getBaseSymbol(symbol);
  return SYMBOL_META[base]?.icon || LOCAL_COIN_ICONS.DEFAULT;
}

function getCoinFallbackIcon(symbol) {
  const base = getBaseSymbol(symbol);

  if (LOCAL_COIN_ICONS[base]) {
    return LOCAL_COIN_ICONS[base];
  }

  const label = String(base || "CO").slice(0, 3).toUpperCase();
  const labelSize = label.length >= 3 ? 34 : label.length === 2 ? 40 : 48;
  return buildCoinBadgeDataUrl({
    bgStart: "#315f9f",
    bgEnd: "#162f56",
    label,
    labelSize
  });
}

function setImageSourceWithFallback(imageElement, primarySrc, fallbackSrc) {
  if (!imageElement) {
    return;
  }

  const resolvedFallback = fallbackSrc || LOCAL_COIN_ICONS.DEFAULT;
  imageElement.onerror = () => {
    imageElement.onerror = null;
    imageElement.src = resolvedFallback;
  };
  imageElement.src = primarySrc || resolvedFallback;
}

function getExchangeInfo(exchange) {
  const key = String(exchange || "").toLowerCase();
  return EXCHANGE_META[key] || { name: key || "unknown", icon: "https://cdn.simpleicons.org/blockchaindotcom/9ea8c3" };
}

function getExchangeBadgeText(exchange) {
  return getDisplayInitials(getExchangeInfo(exchange).name);
}

function safeCurrencyCode(input) {
  const normalized = String(input || "USD").trim().toUpperCase();
  return /^[A-Z]{3,8}$/.test(normalized) ? normalized : "USD";
}

function toSelectedCurrency(valueUsd) {
  const numeric = Number(valueUsd);

  if (!Number.isFinite(numeric)) {
    return Number.NaN;
  }

  const currency = safeCurrencyCode(state.currency);
  const rate = Number(state.fx.rates[currency]);
  const fxRate = Number.isFinite(rate) && rate > 0 ? rate : 1;

  return numeric * fxRate;
}

function formatCurrency(valueUsd, compact = false) {
  const converted = toSelectedCurrency(valueUsd);

  if (!Number.isFinite(converted)) {
    return "-";
  }

  const currency = safeCurrencyCode(state.currency);
  const abs = Math.abs(converted);

  try {
    return new Intl.NumberFormat(getLocale(), {
      style: "currency",
      currency,
      notation: compact ? "compact" : "standard",
      minimumFractionDigits: compact ? 0 : abs >= 100 ? 2 : 4,
      maximumFractionDigits: compact ? 2 : abs >= 100 ? 2 : 6
    }).format(converted);
  } catch {
    return `${converted.toFixed(abs >= 100 ? 2 : 6)} ${currency}`;
  }
}

function formatSpread(valueUsd) {
  const converted = toSelectedCurrency(valueUsd);

  if (!Number.isFinite(converted)) {
    return "-";
  }

  const abs = Math.abs(converted);

  if (abs >= 1) {
    return formatCurrency(valueUsd);
  }

  return `${converted.toFixed(6)} ${safeCurrencyCode(state.currency)}`;
}

function fromSelectedCurrency(valueSelected) {
  const numeric = parseDecimalInput(valueSelected);

  if (!Number.isFinite(numeric)) {
    return Number.NaN;
  }

  const currency = safeCurrencyCode(state.currency);
  const rate = Number(state.fx.rates[currency]);
  const fxRate = Number.isFinite(rate) && rate > 0 ? rate : 1;
  return numeric / fxRate;
}

function getCurrentSymbolPriceUsd(symbol) {
  const normalizedSymbol = String(symbol || "").trim().toUpperCase();
  const aggregate = normalizedSymbol ? state.aggregatesBySymbol.get(normalizedSymbol) : null;
  const price = Number(aggregate?.midPrice);
  return Number.isFinite(price) && price > 0 ? price : Number.NaN;
}

function buildPortfolioAnalytics(user) {
  const portfolio = Array.isArray(user?.portfolio) ? user.portfolio : [];
  const cashUsd = toFiniteNumber(user?.wallet?.usd, 0);
  const positions = portfolio.map((item) => {
    const livePriceUsd = getCurrentSymbolPriceUsd(item.symbol);
    const currentPriceUsd =
      Number.isFinite(livePriceUsd) && livePriceUsd > 0 ? livePriceUsd : toFiniteNumber(item.averageBuyPriceUsd, 0);
    const amount = toFiniteNumber(item.amount, 0);
    const investedUsd = toFiniteNumber(item.investedUsd, 0);
    const currentValueUsd = Math.max(0, amount * currentPriceUsd);
    const pnlUsd = currentValueUsd - investedUsd;

    return {
      ...item,
      amount,
      investedUsd,
      currentPriceUsd,
      currentValueUsd,
      pnlUsd
    };
  });

  const investedUsd = positions.reduce((acc, item) => acc + item.investedUsd, 0);
  const portfolioValueUsd = positions.reduce((acc, item) => acc + item.currentValueUsd, 0);
  const profitLossUsd = positions.reduce((acc, item) => acc + item.pnlUsd, 0);

  return {
    cashUsd,
    investedUsd,
    portfolioValueUsd,
    profitLossUsd,
    totalEquityUsd: cashUsd + portfolioValueUsd,
    positionsCount: positions.length,
    positions
  };
}

function createProfileActivityId() {
  if (typeof crypto !== "undefined" && typeof crypto.randomUUID === "function") {
    return crypto.randomUUID();
  }

  return `activity_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;
}

function getProfileActivityStorageKey(userId) {
  const normalizedUserId = String(userId || "").trim();
  return normalizedUserId ? `${PROFILE_ACTIVITY_STORAGE_PREFIX}:${normalizedUserId}` : "";
}

function normalizeProfileActivityEntry(input) {
  if (!input || typeof input !== "object") {
    return null;
  }

  const type = String(input.type || "").trim().toLowerCase();

  if (type !== "topup" && type !== "buy" && type !== "sell") {
    return null;
  }

  const amountUsd = Number(input.amountUsd);
  const createdAtRaw = String(input.createdAt || "").trim();
  const createdAtMs = Date.parse(createdAtRaw);
  const cardLast4Raw = normalizeCardDigits(input.cardLast4, 4);
  const normalized = {
    id: String(input.id || createProfileActivityId()),
    type,
    createdAt: Number.isFinite(createdAtMs) ? new Date(createdAtMs).toISOString() : new Date().toISOString(),
    amountUsd: Number.isFinite(amountUsd) && amountUsd > 0 ? Math.round(amountUsd * 100) / 100 : 0,
    currency: safeCurrencyCode(input.currency || state.currency),
    symbol: String(input.symbol || "").trim().toUpperCase(),
    assetCode: String(input.assetCode || "").trim().toUpperCase(),
    assetUnits: Number.isFinite(Number(input.assetUnits)) ? Number(input.assetUnits) : 0,
    priceUsd: Number.isFinite(Number(input.priceUsd)) ? Number(input.priceUsd) : 0,
    cardLast4: cardLast4Raw ? cardLast4Raw.slice(-4) : ""
  };

  if (normalized.amountUsd <= 0) {
    return null;
  }

  if ((normalized.type === "buy" || normalized.type === "sell") && (!normalized.symbol || !normalized.assetCode || normalized.assetUnits <= 0)) {
    return null;
  }

  return normalized;
}

function sortProfileActivity(entries) {
  return [...entries].sort((a, b) => Date.parse(b.createdAt) - Date.parse(a.createdAt));
}

function buildSeedProfileActivity(user) {
  if (!user) {
    return [];
  }

  const analytics = buildPortfolioAnalytics(user);
  const entries = [];
  const inferredDepositUsd = analytics.cashUsd + analytics.investedUsd;

  if (inferredDepositUsd > 0) {
    entries.push(
      normalizeProfileActivityEntry({
        id: `seed_topup_${user.id}`,
        type: "topup",
        createdAt: user.createdAt,
        amountUsd: inferredDepositUsd,
        currency: "USD",
        cardLast4: "0000"
      })
    );
  }

  analytics.positions.forEach((position, index) => {
    entries.push(
      normalizeProfileActivityEntry({
        id: `seed_buy_${user.id}_${position.symbol}_${index}`,
        type: "buy",
        createdAt: position.lastBuyAt || user.createdAt,
        amountUsd: position.investedUsd,
        symbol: position.symbol,
        assetCode: position.assetCode,
        assetUnits: position.amount,
        priceUsd: position.averageBuyPriceUsd,
        currency: "USD"
      })
    );
  });

  return sortProfileActivity(entries.filter(Boolean));
}

function loadProfileActivityForUser(user) {
  if (!user?.id) {
    return [];
  }

  const storageKey = getProfileActivityStorageKey(user.id);

  if (!storageKey) {
    return [];
  }

  try {
    const raw = String(localStorage.getItem(storageKey) || "").trim();

    if (!raw) {
      const seeded = buildSeedProfileActivity(user);

      if (seeded.length) {
        localStorage.setItem(storageKey, JSON.stringify(seeded));
      }

      return seeded;
    }

    const parsed = JSON.parse(raw);
    const entries = Array.isArray(parsed) ? parsed.map(normalizeProfileActivityEntry).filter(Boolean) : [];

    if (entries.length) {
      return sortProfileActivity(entries);
    }
  } catch {
    // ignore malformed local activity cache
  }

  const seeded = buildSeedProfileActivity(user);

  if (seeded.length) {
    try {
      localStorage.setItem(storageKey, JSON.stringify(seeded));
    } catch {
      // ignore localStorage persistence errors
    }
  }

  return seeded;
}

function saveProfileActivityForUser(userId, entries) {
  const storageKey = getProfileActivityStorageKey(userId);

  if (!storageKey) {
    return;
  }

  try {
    localStorage.setItem(storageKey, JSON.stringify(sortProfileActivity(entries)));
  } catch {
    // ignore localStorage persistence errors
  }
}

function syncProfileActivityFromAuthUser(user) {
  state.profileActivity = loadProfileActivityForUser(user);
}

function appendProfileActivity(entryInput) {
  if (!state.auth.user?.id) {
    return;
  }

  const entry = normalizeProfileActivityEntry(entryInput);

  if (!entry) {
    return;
  }

  state.profileActivity = sortProfileActivity([entry, ...state.profileActivity]);
  saveProfileActivityForUser(state.auth.user.id, state.profileActivity);
  renderProfileActivityHistory();
}

function renderProfileActivityHistory() {
  if (!refs.profileActivityHistory) {
    return;
  }

  if (!state.auth.user || !state.profileActivity.length) {
    refs.profileActivityHistory.innerHTML = `<div class="profileActivityEmpty">${t("profile.activityEmpty")}</div>`;
    return;
  }

  refs.profileActivityHistory.innerHTML = state.profileActivity
    .map((entry) => {
      const isTrade = entry.type === "buy" || entry.type === "sell";
      const badgeText =
        entry.type === "buy"
          ? t("profile.activityTypeBuy")
          : entry.type === "sell"
            ? t("profile.activityTypeSell")
            : t("profile.activityTypeTopup");
      const titleText = isTrade
        ? `${getDisplayName(entry.symbol)} В· ${formatSymbolPair(entry.symbol)}`
        : t("profile.activityTypeTopup");
      const stats = [];

      stats.push(`
        <div class="profileActivityStat">
          <span>${t("profile.activityAmount")}</span>
          <strong>${formatCurrency(entry.amountUsd)}</strong>
        </div>
      `);

      if (isTrade) {
        stats.push(`
          <div class="profileActivityStat">
            <span>${t("profile.activityUnits")}</span>
            <strong>${formatCryptoAmount(entry.assetUnits, entry.assetCode || getBaseSymbol(entry.symbol) || "UNIT")}</strong>
          </div>
        `);
        stats.push(`
          <div class="profileActivityStat">
            <span>${t("profile.activityPrice")}</span>
            <strong>${formatCurrency(entry.priceUsd)}</strong>
          </div>
        `);
      } else if (entry.cardLast4) {
        stats.push(`
          <div class="profileActivityStat">
            <span>${t("profile.activityCard")}</span>
            <strong>вҖўвҖўвҖўвҖў ${entry.cardLast4}</strong>
          </div>
        `);
      }

      stats.push(`
        <div class="profileActivityStat">
          <span>${t("profile.activityTime")}</span>
          <strong>${formatDateTime(Date.parse(entry.createdAt))}</strong>
        </div>
      `);

      return `
        <article class="profileActivityCard">
          <div class="profileActivityTop">
            <div class="profileActivityType">
              <span class="profileActivityTypeBadge">${badgeText}</span>
              <strong>${titleText}</strong>
            </div>
            <div class="profileActivityMeta">${formatDateTime(Date.parse(entry.createdAt))}</div>
          </div>
          <div class="profileActivityStats">
            ${stats.join("")}
          </div>
        </article>
      `;
    })
    .join("");
}

function escapeHtml(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function getSelectedReportType() {
  const value = String(refs.reportTypeSelect?.value || "full").trim();
  return ["full", "profile", "portfolio", "market", "security"].includes(value) ? value : "full";
}

function getReportRecipientEmails() {
  const raw = String(refs.reportRecipientEmail?.value || state.auth.user?.email || "").trim();
  return raw
    .split(/[;,]/)
    .map((item) => item.trim().toLowerCase())
    .filter(Boolean);
}

function isValidReportEmail(value) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(String(value || "").trim());
}

function areValidReportEmails(values) {
  return Array.isArray(values) && values.length > 0 && values.length <= 8 && values.every(isValidReportEmail);
}

function getReportQueryString() {
  const params = new URLSearchParams();
  params.set("type", getSelectedReportType());
  params.set("includeProfile", refs.reportIncludeProfile?.checked === false ? "false" : "true");
  return params.toString();
}

function setReportShareUrl(url) {
  if (!refs.reportShareBox || !refs.reportShareUrl) {
    return;
  }

  const value = String(url || "").trim();
  refs.reportShareUrl.value = value;
  refs.reportShareBox.classList.toggle("hidden", !value);
}

function setProfileReportStatus(text, isError = false) {
  if (!refs.profileReportStatus) {
    return;
  }
  refs.profileReportStatus.textContent = text;
  refs.profileReportStatus.classList.toggle("hidden", !text);
  refs.profileReportStatus.style.color = isError
    ? (getComputedStyle(refs.root).getPropertyValue("--red").trim() || "#ff6f78")
    : (getComputedStyle(refs.root).getPropertyValue("--muted").trim() || "#98aed3");
}

function getReportReasonText(reason) {
  const normalized = String(reason || "").trim();
  const reasonKeyByText = {
    "Market coverage is active": "reports.reason.market",
    "Multiple exchanges are online": "reports.reason.exchanges",
    "Watchlist is configured": "reports.reason.watchlist",
    "Portfolio contains open positions": "reports.reason.portfolio",
    "Price alerts are configured": "reports.reason.alerts",
    "Webhook automation is configured": "reports.reason.webhooks",
    "Account is ready for first setup": "reports.reason.empty"
  };
  return t(reasonKeyByText[normalized] || normalized);
}

function getReportSectionTitle(section) {
  const key = String(section?.key || '').trim();
  const mapped = key ? t(`reports.section.${key}Title`) : '';
  return mapped && mapped !== `reports.section.${key}Title` ? mapped : String(section?.title || key || 'Section');
}

function getReportSectionSummary(section) {
  const key = String(section?.key || '').trim();
  const mapped = key ? t(`reports.section.${key}Text`) : '';
  return mapped && mapped !== `reports.section.${key}Text` ? mapped : String(section?.summary || '');
}

function renderReportInsights(report) {
  if (!refs.reportInsightList) {
    return;
  }
  const reasons = Array.isArray(report?.score?.reasons) ? report.score.reasons : [];
  const recommendations = Array.isArray(report?.recommendations) ? report.recommendations : [];
  const items = [...reasons.map(getReportReasonText), ...recommendations].filter(Boolean).slice(0, 8);
  refs.reportInsightList.innerHTML = (items.length ? items : [t("reports.empty")])
    .map((item) => `<li>${escapeHtml(item)}</li>`)
    .join("");
}

function renderProfileReportSummary() {
  if (!refs.profileReportSummary) {
    return;
  }
  const report = state.profileReport;
  if (!state.auth.user) {
    if (refs.reportHeroScoreValue) refs.reportHeroScoreValue.textContent = "-";
    refs.profileReportSummary.innerHTML = `<div class="profileActivityEmpty">${t("reports.authRequired")}</div>`;
    if (refs.reportInsightList) refs.reportInsightList.innerHTML = `<li>${escapeHtml(t("reports.authRequired"))}</li>`;
    return;
  }
  if (!report) {
    if (refs.reportHeroScoreValue) refs.reportHeroScoreValue.textContent = "-";
    refs.profileReportSummary.innerHTML = `<div class="profileActivityEmpty">${t("reports.empty")}</div>`;
    if (refs.reportInsightList) refs.reportInsightList.innerHTML = `<li>${escapeHtml(t("reports.empty"))}</li>`;
    return;
  }
  const score = Number(report?.score?.value);
  const pnl = Number(report?.portfolio?.summary?.unrealizedPnlUsd);
  const reasons = Array.isArray(report?.score?.reasons) ? report.score.reasons : [];
  const sections = Array.isArray(report?.sections) ? report.sections : [];
  const recommendations = Array.isArray(report?.recommendations) ? report.recommendations : [];
  if (refs.reportHeroScoreValue) refs.reportHeroScoreValue.textContent = Number.isFinite(score) ? `${score}/100` : "-";
  renderReportInsights(report);
  refs.profileReportSummary.innerHTML = `
    <article class="reportMetricCard"><span>${t("reports.score")}</span><strong>${Number.isFinite(score) ? `${score}/100` : "-"}</strong></article>
    <article class="reportMetricCard"><span>${t("reports.market")}</span><strong>${formatCompactNumber(Number(report?.market?.symbolsTracked ?? 0))}</strong></article>
    <article class="reportMetricCard"><span>${t("reports.exchanges")}</span><strong>${formatCompactNumber(Number(report?.market?.activeExchanges ?? 0))}</strong></article>
    <article class="reportMetricCard"><span>${t("reports.positions")}</span><strong>${formatCompactNumber(Number(report?.portfolio?.summary?.trackedPositions ?? 0))}</strong></article>
    <article class="reportMetricCard"><span>${t("reports.pnl")}</span><strong>${Number.isFinite(pnl) ? formatCurrency(pnl) : "-"}</strong></article>
    <article class="reportMetricCard"><span>${t("reports.alerts")}</span><strong>${formatCompactNumber(Number(report?.alerts?.length ?? 0))}</strong></article>
    <article class="reportMetricCard"><span>${t("reports.webhooks")}</span><strong>${formatCompactNumber(Number(report?.webhooks?.length ?? 0))}</strong></article>
    <article class="reportMetricCard"><span>${t("reports.generatedAt")}</span><strong>${formatDateTime(Date.parse(report.generatedAt))}</strong></article>
    <div class="reportTextBlock"><strong>${t("reports.recommendations")}</strong><ul class="reportReasonList">${(recommendations.length ? recommendations : reasons).map((item) => `<li>${escapeHtml(getReportReasonText(item))}</li>`).join("")}</ul></div>
    <div class="reportTextBlock"><strong>${t("reports.sections")}</strong><ul class="reportReasonList">${(sections.length ? sections : []).map((item) => `<li><b>${escapeHtml(getReportSectionTitle(item))}</b>: ${escapeHtml(getReportSectionSummary(item))}</li>`).join("") || `<li>${escapeHtml(t("reports.empty"))}</li>`}</ul></div>
  `;
}

async function generateProfileReport({ silent = false } = {}) {
  if (!state.auth.user || !state.auth.token) {
    setProfileReportStatus(t("reports.authRequired"), true);
    return null;
  }
  if (!silent) setProfileReportStatus(t("reports.generating"));
  const payload = await fetchJson(`/api/v1/auth/reports/overview?${getReportQueryString()}`, {
    headers: { Authorization: `Bearer ${state.auth.token}` }
  });
  state.profileReport = payload.data || null;
  setReportShareUrl("");
  renderProfileReportSummary();
  if (!silent) setProfileReportStatus(t("reports.generated"));
  return state.profileReport;
}

async function sendProfileReportEmail() {
  if (!state.auth.user || !state.auth.token) {
    setProfileReportStatus(t("reports.authRequired"), true);
    return;
  }
  const recipientEmails = getReportRecipientEmails();
  if (!recipientEmails.length) {
    setProfileReportStatus(t("reports.emailMissing"), true);
    refs.reportRecipientEmail?.focus();
    return;
  }
  if (!areValidReportEmails(recipientEmails)) {
    setProfileReportStatus(t("reports.emailInvalid"), true);
    refs.reportRecipientEmail?.focus();
    return;
  }
  setProfileReportStatus(t("reports.sending"));
  if (!state.profileReport) await generateProfileReport({ silent: true });
  const payload = await fetchJson("/api/v1/auth/reports/email", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${state.auth.token}`
    },
    body: JSON.stringify({
      recipientEmail: recipientEmails,
      reportType: getSelectedReportType(),
      includeProfile: refs.reportIncludeProfile?.checked !== false,
      language: state.lang
    })
  });
  setProfileReportStatus(t("reports.sent", { email: payload.sentTo || recipientEmails.join(", ") }));
}

function downloadBlob(blob, fileName) {
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = fileName;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
}

function getReportFileStamp(report) {
  return new Date(report?.generatedAt || Date.now()).toISOString().replace(/[:.]/g, "-");
}

async function downloadProfileReport() {
  const report = state.profileReport || (await generateProfileReport({ silent: true }));

  if (!report) {
    return;
  }

  const blob = new Blob([JSON.stringify(report, null, 2)], { type: "application/json;charset=utf-8" });
  downloadBlob(blob, "cryptoaggregator-report-" + getReportFileStamp(report) + ".json");
  setProfileReportStatus(t("reports.downloaded"));
}

function buildReportHtmlDocument(report) {
  const sections = Array.isArray(report?.sections) ? report.sections : [];
  const recommendations = Array.isArray(report?.recommendations) ? report.recommendations : [];
  const topSymbols = Array.isArray(report?.market?.topSymbols) ? report.market.topSymbols : [];
  const positions = Array.isArray(report?.portfolio?.positions) ? report.portfolio.positions : [];
  const exchanges = Array.isArray(report?.exchanges) ? report.exchanges : [];
  const alerts = Array.isArray(report?.alerts) ? report.alerts : [];
  const webhooks = Array.isArray(report?.webhooks) ? report.webhooks : [];
  const generated = report?.generatedAt ? formatDateTime(Date.parse(report.generatedAt)) : formatDateTime(Date.now());
  const metric = (label, value) => '<article><span>' + escapeHtml(label) + '</span><strong>' + escapeHtml(value) + '</strong></article>';
  const table = (title, headers, rows) => {
    const body = rows.length
      ? rows.map((row) => '<tr>' + row.map((cell) => '<td>' + escapeHtml(String(cell ?? '-')) + '</td>').join('') + '</tr>').join('')
      : '<tr><td colspan="' + headers.length + '">' + escapeHtml(t('common.noData')) + '</td></tr>';
    return '<section><h2>' + escapeHtml(title) + '</h2><table><thead><tr>' + headers.map((item) => '<th>' + escapeHtml(item) + '</th>').join('') + '</tr></thead><tbody>' + body + '</tbody></table></section>';
  };
  const sectionHtml = sections.length
    ? sections.map((section) => '<section><h2>' + escapeHtml(getReportSectionTitle(section)) + '</h2><p>' + escapeHtml(getReportSectionSummary(section)) + '</p><ul>' + (Array.isArray(section.items) ? section.items : []).map((item) => '<li>' + escapeHtml(item) + '</li>').join('') + '</ul></section>').join('')
    : '<section><h2>' + escapeHtml(t('reports.sections')) + '</h2><p>' + escapeHtml(t('reports.empty')) + '</p></section>';
  const recommendationsHtml = recommendations.length
    ? recommendations.map((item) => '<li>' + escapeHtml(getReportReasonText(item)) + '</li>').join('')
    : '<li>' + escapeHtml(t('reports.empty')) + '</li>';
  const topSymbolsHtml = table(t('reports.topSymbols'), [t('reports.col.symbol'), t('reports.col.price'), t('table.spread'), t('reports.col.quality'), t('reports.col.sources')], topSymbols.map((item) => [item.symbol || '-', formatCurrency(Number(item.priceUsd)), formatCurrency(Number(item.spreadUsd)), item.quality || '-', item.activeSources ?? '-']));
  const portfolioHtml = table(t('profile.holdingsTitle'), [t('table.ticker'), t('profile.holdingUnits'), t('profile.holdingInvested'), t('profile.holdingCurrentValue'), t('profile.pnl')], positions.map((item) => [item.symbol || '-', formatCryptoAmount(Number(item.amount), item.assetCode || ''), formatCurrency(Number(item.investedUsd)), formatCurrency(Number(item.currentValueUsd)), formatCurrency(Number(item.unrealizedPnlUsd))]));
  const exchangeHtml = table(t('exchanges.health.title'), [t('exchanges.health.col.exchange'), t('exchanges.health.col.status'), t('exchanges.health.col.qualityScore'), t('exchanges.health.col.avgLatency'), t('exchanges.health.col.errors')], exchanges.slice(0, 20).map((item) => [item.exchange || '-', item.status || '-', String(item.qualityScore ?? '-') + '/100', String(Math.round(Number(item.averageLatencyMs || 0))) + ' ms', item.errorCount ?? 0]));
  const alertsHtml = table(t('features.alertsTitle'), [t('table.ticker'), t('features.condition'), t('features.targetPrice'), t('features.channels'), t('features.enabled')], alerts.map((item) => [item.symbol || '-', item.direction || '-', formatCurrency(Number(item.targetPrice)), Array.isArray(item.channels) ? item.channels.join(', ') : '-', item.enabled ? 'OK' : '-']));
  const webhooksHtml = table(t('features.webhooksTitle'), ['URL', t('table.ticker'), t('features.condition'), t('features.targetPrice'), t('features.enabled')], webhooks.map((item) => [item.url || '-', item.symbol || '-', item.direction || '-', formatCurrency(Number(item.targetPrice)), item.enabled ? 'OK' : '-']));

  return '<!doctype html><html lang="' + escapeHtml(state.lang || 'uk') + '"><head><meta charset="utf-8"><title>' + escapeHtml(t('reports.documentTitle')) + '</title><style>' +
    'body{margin:0;padding:34px;background:#071225;color:#f7fbff;font-family:Arial,sans-serif}main{max-width:1120px;margin:auto}.hero{padding:28px;border-radius:24px;background:linear-gradient(135deg,#132d58,#0b1832);border:1px solid #2c5da8}h1{margin:0 0 8px;font-size:34px}p{color:#b8c8e8}.metrics{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:12px;margin:20px 0}.metrics article,section{padding:16px;border-radius:18px;background:#0b1832;border:1px solid #2c5da8}.metrics span{display:block;color:#9ab2dc;font-size:12px}.metrics strong{display:block;margin-top:6px;font-size:22px}section{margin-top:14px}table{width:100%;border-collapse:collapse;margin-top:12px;table-layout:auto}th,td{padding:10px;border-bottom:1px solid #284b82;text-align:left;vertical-align:top}th{color:#9cc2ff}.watermark{margin-top:24px;color:#7f96bd;font-size:12px}@media print{body{background:white;color:#111}.hero,.metrics article,section{background:white;color:#111;border-color:#ccc}p,.metrics span,.watermark{color:#555}}' +
    '</style></head><body><main><div class="hero"><h1>' + escapeHtml(t('reports.pageTitle')) + '</h1><p>' + escapeHtml(t('reports.pageSubtitle')) + '</p><p>' + escapeHtml(t('reports.generatedAt')) + ': ' + escapeHtml(generated) + '</p></div><div class="metrics">' +
    metric(t('reports.score'), String(report?.score?.value ?? '-') + '/100') +
    metric(t('reports.market'), String(report?.market?.symbolsTracked ?? '-')) +
    metric(t('reports.exchanges'), String(report?.market?.activeExchanges ?? '-')) +
    metric(t('reports.positions'), String(report?.portfolio?.summary?.trackedPositions ?? '-')) +
    metric(t('reports.pnl'), formatCurrency(Number(report?.portfolio?.summary?.unrealizedPnlUsd ?? 0))) +
    metric(t('reports.alerts'), String(alerts.length)) +
    metric(t('reports.webhooks'), String(webhooks.length)) +
    '</div>' + sectionHtml + '<section><h2>' + escapeHtml(t('reports.recommendations')) + '</h2><ul>' + recommendationsHtml + '</ul></section>' + topSymbolsHtml + portfolioHtml + exchangeHtml + alertsHtml + webhooksHtml + '<p class="watermark">' + escapeHtml(t('reports.generatedBy')) + '</p></main></body></html>';
}

function encodePdfUtf16Hex(value) {
  const text = String(value ?? '');
  let hex = 'FEFF';

  for (let i = 0; i < text.length; i += 1) {
    hex += text.charCodeAt(i).toString(16).padStart(4, '0').toUpperCase();
  }

  return '<' + hex + '>';
}

function wrapPdfLine(line, maxChars = 92) {
  const value = String(line ?? '').replace(/\s+/g, ' ').trim();

  if (!value) {
    return [''];
  }

  const words = value.split(' ');
  const rows = [];
  let current = '';

  for (const word of words) {
    const next = current ? current + ' ' + word : word;
    if (next.length > maxChars && current) {
      rows.push(current);
      current = word;
    } else {
      current = next;
    }
  }

  if (current) {
    rows.push(current);
  }

  return rows;
}

function buildReportPdfLines(report) {
  const sections = Array.isArray(report?.sections) ? report.sections : [];
  const recommendations = Array.isArray(report?.recommendations) ? report.recommendations : [];
  const topSymbols = Array.isArray(report?.market?.topSymbols) ? report.market.topSymbols : [];
  const positions = Array.isArray(report?.portfolio?.positions) ? report.portfolio.positions : [];
  const exchanges = Array.isArray(report?.exchanges) ? report.exchanges : [];
  const alerts = Array.isArray(report?.alerts) ? report.alerts : [];
  const webhooks = Array.isArray(report?.webhooks) ? report.webhooks : [];
  const generated = report?.generatedAt ? formatDateTime(Date.parse(report.generatedAt)) : formatDateTime(Date.now());
  const lines = [
    t('reports.documentTitle'),
    t('reports.generatedAt') + ': ' + generated,
    '',
    t('reports.score') + ': ' + String(report?.score?.value ?? '-') + '/100',
    t('reports.market') + ': ' + String(report?.market?.symbolsTracked ?? '-'),
    t('reports.exchanges') + ': ' + String(report?.market?.activeExchanges ?? '-'),
    t('reports.positions') + ': ' + String(report?.portfolio?.summary?.trackedPositions ?? '-'),
    t('reports.pnl') + ': ' + formatCurrency(Number(report?.portfolio?.summary?.unrealizedPnlUsd ?? 0)),
    t('reports.alerts') + ': ' + String(alerts.length),
    t('reports.webhooks') + ': ' + String(webhooks.length),
    ''
  ];

  lines.push(t('reports.sections'));
  sections.forEach((section) => {
    lines.push('- ' + getReportSectionTitle(section));
    lines.push('  ' + getReportSectionSummary(section));
    (Array.isArray(section.items) ? section.items : []).forEach((item) => lines.push('  * ' + item));
  });

  lines.push('', t('reports.recommendations'));
  (recommendations.length ? recommendations : [t('reports.empty')]).forEach((item) => lines.push('- ' + getReportReasonText(item)));

  lines.push('', t('reports.topSymbols'));
  topSymbols.slice(0, 12).forEach((item) => {
    lines.push('- ' + (item.symbol || '-') + ' | ' + formatCurrency(Number(item.priceUsd)) + ' | ' + t('table.spread') + ': ' + formatCurrency(Number(item.spreadUsd)) + ' | ' + t('reports.col.quality') + ': ' + (item.quality || '-') + ' | ' + t('reports.col.sources') + ': ' + (item.activeSources ?? '-'));
  });

  lines.push('', t('profile.holdingsTitle'));
  (positions.length ? positions : []).forEach((item) => {
    lines.push('- ' + (item.symbol || '-') + ' | ' + t('profile.holdingUnits') + ': ' + formatCryptoAmount(Number(item.amount), item.assetCode || '') + ' | ' + t('profile.holdingInvested') + ': ' + formatCurrency(Number(item.investedUsd)) + ' | ' + t('profile.pnl') + ': ' + formatCurrency(Number(item.unrealizedPnlUsd)));
  });
  if (!positions.length) lines.push('- ' + t('common.noData'));

  lines.push('', t('exchanges.health.title'));
  exchanges.slice(0, 16).forEach((item) => {
    lines.push('- ' + (item.exchange || '-') + ' | ' + (item.status || '-') + ' | ' + String(item.qualityScore ?? '-') + '/100 | ' + String(Math.round(Number(item.averageLatencyMs || 0))) + ' ms | errors: ' + (item.errorCount ?? 0));
  });

  lines.push('', t('features.alertsTitle'));
  (alerts.length ? alerts : []).forEach((item) => lines.push('- ' + (item.symbol || '-') + ' | ' + (item.direction || '-') + ' | ' + formatCurrency(Number(item.targetPrice))));
  if (!alerts.length) lines.push('- ' + t('common.noData'));

  lines.push('', t('features.webhooksTitle'));
  (webhooks.length ? webhooks : []).forEach((item) => lines.push('- ' + (item.url || '-') + ' | ' + (item.symbol || '-') + ' | ' + (item.direction || '-') + ' | ' + formatCurrency(Number(item.targetPrice))));
  if (!webhooks.length) lines.push('- ' + t('common.noData'));

  lines.push('', t('reports.generatedBy'));
  return lines;
}

function buildReportPdfBlob(report) {
  const wrappedLines = buildReportPdfLines(report).flatMap((line) => wrapPdfLine(line));
  const pageWidth = 595;
  const pageHeight = 842;
  const marginX = 42;
  const lineHeight = 14;
  const firstY = 792;
  const linesPerPage = 52;
  const pages = [];

  for (let i = 0; i < wrappedLines.length; i += linesPerPage) {
    pages.push(wrappedLines.slice(i, i + linesPerPage));
  }

  if (!pages.length) {
    pages.push([t('reports.empty')]);
  }

  const objects = [];
  const setObject = (id, body) => { objects[id] = body; };
  setObject(1, '<< /Type /Catalog /Pages 2 0 R >>');
  setObject(3, '<< /Type /FontDescriptor /FontName /ArialUnicodeMS /Flags 32 /FontBBox [-1000 -300 2000 1000] /ItalicAngle 0 /Ascent 900 /Descent -250 /CapHeight 700 /StemV 80 >>');
  setObject(4, '<< /Type /Font /Subtype /CIDFontType2 /BaseFont /ArialUnicodeMS /CIDSystemInfo << /Registry (Adobe) /Ordering (Identity) /Supplement 0 >> /FontDescriptor 3 0 R >>');
  setObject(5, '<< /Type /Font /Subtype /Type0 /BaseFont /ArialUnicodeMS /Encoding /Identity-H /DescendantFonts [4 0 R] >>');

  const pageIds = [];
  let nextId = 6;
  pages.forEach((pageLines, pageIndex) => {
    const commands = pageLines.map((line, index) => {
      const size = pageIndex === 0 && index === 0 ? 18 : 10;
      const y = firstY - index * lineHeight;
      return 'BT /F1 ' + size + ' Tf ' + marginX + ' ' + y + ' Td ' + encodePdfUtf16Hex(line) + ' Tj ET';
    }).join('\n');
    const contentId = nextId++;
    const pageId = nextId++;
    setObject(contentId, '<< /Length ' + commands.length + ' >>\nstream\n' + commands + '\nendstream');
    setObject(pageId, '<< /Type /Page /Parent 2 0 R /MediaBox [0 0 ' + pageWidth + ' ' + pageHeight + '] /Resources << /Font << /F1 5 0 R >> >> /Contents ' + contentId + ' 0 R >>');
    pageIds.push(pageId);
  });
  setObject(2, '<< /Type /Pages /Kids [' + pageIds.map((id) => id + ' 0 R').join(' ') + '] /Count ' + pageIds.length + ' >>');

  let pdf = '%PDF-1.7\n%PDFGEN\n';
  const offsets = [0];
  for (let id = 1; id < objects.length; id += 1) {
    offsets[id] = pdf.length;
    pdf += id + ' 0 obj\n' + objects[id] + '\nendobj\n';
  }
  const xrefOffset = pdf.length;
  pdf += 'xref\n0 ' + objects.length + '\n0000000000 65535 f \n';
  for (let id = 1; id < objects.length; id += 1) {
    pdf += String(offsets[id]).padStart(10, '0') + ' 00000 n \n';
  }
  pdf += 'trailer\n<< /Size ' + objects.length + ' /Root 1 0 R >>\nstartxref\n' + xrefOffset + '\n%%EOF';
  return new Blob([pdf], { type: 'application/pdf' });
}

function getDownloadFileName(response, fallback) {
  const disposition = response.headers.get('Content-Disposition') || response.headers.get('content-disposition') || '';
  const utf8Match = disposition.match(/filename\*=UTF-8''([^;]+)/i);
  const plainMatch = disposition.match(/filename="?([^";]+)"?/i);

  if (utf8Match?.[1]) {
    try {
      return decodeURIComponent(utf8Match[1]);
    } catch {
      return utf8Match[1];
    }
  }

  return plainMatch?.[1] || fallback;
}

async function downloadProfileReportAttachment(kind, extension, statusKey) {
  if (!state.auth.user || !state.auth.token) {
    setProfileReportStatus(t("reports.authRequired"), true);
    return;
  }

  const report = state.profileReport || (await generateProfileReport({ silent: true }));

  if (!report) {
    return;
  }

  const response = await fetch('/api/v1/auth/reports/' + kind, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: 'Bearer ' + state.auth.token
    },
    body: JSON.stringify({
      reportType: getSelectedReportType(),
      includeProfile: refs.reportIncludeProfile?.checked !== false,
      language: state.lang
    })
  });

  if (!response.ok) {
    let message = t("reports.emailUnavailable");
    try {
      const payload = await response.json();
      message = payload.error || message;
    } catch {
      message = (await response.text()) || message;
    }
    throw new Error(message);
  }

  const blob = await response.blob();
  const fallback = 'cryptoaggregator-report-' + getReportFileStamp(report) + '.' + extension;
  downloadBlob(blob, getDownloadFileName(response, fallback));
  setProfileReportStatus(t(statusKey));
}

async function downloadProfileReportPdf() {
  await downloadProfileReportAttachment('pdf', 'pdf', 'reports.pdfDownloaded');
}

async function downloadProfileReportWord() {
  await downloadProfileReportAttachment('word', 'doc', 'reports.wordDownloaded');
}

async function createReportShareLink() {
  if (!state.auth.user || !state.auth.token) {
    setProfileReportStatus(t('reports.authRequired'), true);
    return;
  }

  setProfileReportStatus(t('reports.shareCreating'));
  const payload = await fetchJson('/api/v1/auth/reports/share', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: 'Bearer ' + state.auth.token
    },
    body: JSON.stringify({
      reportType: getSelectedReportType(),
      includeProfile: refs.reportIncludeProfile?.checked !== false,
      language: state.lang
    })
  });

  const shareUrl = payload.shortUrl || payload.url;

  if (!shareUrl) {
    throw new Error(t('reports.shareUnavailable'));
  }

  setReportShareUrl(shareUrl);
  setProfileReportStatus(payload.public === false ? t('reports.shareLocalOnly') : t('reports.shareReady'), payload.public === false);
}

async function copyReportShareLink() {
  const value = String(refs.reportShareUrl?.value || '').trim();

  if (!value) {
    return;
  }

  try {
    await navigator.clipboard.writeText(value);
    setProfileReportStatus(t('reports.shareCopied'));
  } catch {
    refs.reportShareUrl?.select();
    setProfileReportStatus(t('reports.shareReady'));
  }
}

function renderPortfolioPositions() {
  if (!refs.profileHoldingsList) {
    return;
  }

  const analytics = buildPortfolioAnalytics(state.auth.user);

  if (!analytics.positions.length) {
    refs.profileHoldingsList.innerHTML = `<div class="portfolioEmpty">${t("profile.holdingsEmpty")}</div>`;
    return;
  }

  refs.profileHoldingsList.innerHTML = analytics.positions
    .map((position) => {
      const name = getDisplayName(position.symbol);
      const pnlClass = position.pnlUsd >= 0 ? "positive" : "negative";
      const fallbackIcon = getCoinFallbackIcon(position.symbol);
      return `
        <article class="holdingCard">
          <div class="holdingTop">
            <div class="holdingAsset">
              <img class="assetIcon" src="${getCoinIcon(position.symbol)}" alt="${name}" loading="lazy" decoding="async" data-fallback-src="${fallbackIcon}" onerror="this.onerror=null;this.src=this.dataset.fallbackSrc;" />
              <div>
                <strong>${name}</strong>
                <div class="holdingSymbol">${formatSymbolPair(position.symbol)}</div>
              </div>
            </div>
            <div class="holdingPnl ${pnlClass}">
              ${formatCurrency(position.pnlUsd)}
            </div>
          </div>
          <div class="holdingStats">
            <div class="holdingStat">
              <span>${t("profile.holdingUnits")}</span>
              <strong>${formatCryptoAmount(position.amount, position.assetCode)}</strong>
            </div>
            <div class="holdingStat">
              <span>${t("profile.holdingInvested")}</span>
              <strong>${formatCurrency(position.investedUsd)}</strong>
            </div>
            <div class="holdingStat">
              <span>${t("profile.holdingCurrentValue")}</span>
              <strong>${formatCurrency(position.currentValueUsd)}</strong>
            </div>
            <div class="holdingStat">
              <span>${t("profile.holdingAvgPrice")}</span>
              <strong>${formatCurrency(position.averageBuyPriceUsd)}</strong>
            </div>
          </div>
        </article>
      `;
    })
    .join("");
}

function renderInvestmentDraftInfo() {
  if (!refs.profileInvestPrice || !refs.profileInvestUnits || !refs.profileCashAvailable || !refs.profileInvestBtn) {
    return;
  }

  const selectedSymbol = String(refs.profileInvestSymbol?.value || state.profileInvestSymbol || "").trim().toUpperCase();
  const priceUsd = getCurrentSymbolPriceUsd(selectedSymbol);
  const selectedAmount = String(refs.profileInvestAmount?.value || "");
  const amountUsd = fromSelectedCurrency(selectedAmount);
  const assetCode = getBaseSymbol(selectedSymbol) || "";
  const units = Number.isFinite(priceUsd) && priceUsd > 0 && Number.isFinite(amountUsd) && amountUsd > 0 ? amountUsd / priceUsd : Number.NaN;
  const availableCashUsd = toFiniteNumber(state.auth.user?.wallet?.usd, 0);

  refs.profileInvestPrice.textContent =
    Number.isFinite(priceUsd) && priceUsd > 0 ? `${formatCurrency(priceUsd)} В· ${formatSymbolPair(selectedSymbol)}` : "-";
  refs.profileInvestUnits.textContent =
    Number.isFinite(units) && units > 0 ? formatCryptoAmount(units, assetCode || "UNIT") : formatCryptoAmount(0, assetCode || "UNIT");
  refs.profileCashAvailable.textContent = formatCurrency(availableCashUsd);
  refs.profileInvestBtn.disabled = !state.auth.user || !selectedSymbol || !Number.isFinite(priceUsd) || priceUsd <= 0;
}

function applyGuestExperience() {
  const isGuest = !state.auth.user;

  refs.body?.classList.toggle("guestMode", isGuest);
  refs.guestUnlockBanner?.classList.toggle("hidden", !isGuest);

  refs.guestLockedPanels.forEach((panel) => {
    panel.classList.toggle("guestLockedPanel", isGuest);
    panel.setAttribute("data-guest-title", t("guest.lockTitle"));
    panel.setAttribute("data-guest-copy", t("guest.lockMessage"));
    panel.setAttribute("aria-label", `${t("guest.lockTitle")}. ${t("guest.lockMessage")}`);

    if (isGuest) {
      panel.setAttribute("tabindex", "0");
    } else {
      panel.removeAttribute("tabindex");
    }
  });
}

function openRegistrationPrompt(prefillEmail = "") {
  showAuthModal("register");
  setAuthStatus(t("guest.authHint"));

  if (prefillEmail && refs.registerEmail) {
    refs.registerEmail.value = prefillEmail;
  }

  refs.registerDisplayName?.focus();
}

function openInvestmentFlow(symbol) {
  const normalizedSymbol = String(symbol || "").trim().toUpperCase();

  if (!state.auth.user) {
    openRegistrationPrompt();
    return;
  }

  if (normalizedSymbol) {
    state.profileInvestSymbol = normalizedSymbol;
  }

  showProfileModal();
  refs.profileInvestAmount?.focus();
}

function formatCompactNumber(value) {
  if (!Number.isFinite(value)) {
    return "-";
  }

  return new Intl.NumberFormat(getLocale(), {
    notation: "compact",
    maximumFractionDigits: 2
  }).format(value);
}

function formatClock(tsMs) {
  if (!Number.isFinite(tsMs)) {
    return "-";
  }

  return new Date(tsMs).toLocaleTimeString(getLocale());
}

function formatDateTime(tsMs) {
  if (!Number.isFinite(tsMs)) {
    return "-";
  }

  return new Date(tsMs).toLocaleString(getLocale());
}

function toOptionalFiniteNumber(input) {
  if (input === null || input === undefined || input === "") {
    return Number.NaN;
  }

  const numeric = Number(input);
  return Number.isFinite(numeric) ? numeric : Number.NaN;
}

function normalizeTickStaleAfterMs(input, fallback = DEFAULT_TICK_STALE_AFTER_MS) {
  const numeric = Number(input);

  if (Number.isFinite(numeric) && numeric > 0) {
    return Math.trunc(numeric);
  }

  const fallbackNumeric = Number(fallback);
  return Number.isFinite(fallbackNumeric) && fallbackNumeric > 0
    ? Math.trunc(fallbackNumeric)
    : DEFAULT_TICK_STALE_AFTER_MS;
}

function resolveAggregateQuality(inputQuality, activeSourcesInput) {
  const quality = String(inputQuality || "").trim().toLowerCase();

  if (quality === "high" || quality === "medium" || quality === "low") {
    return quality;
  }

  const activeSources = Number(activeSourcesInput);

  if (Number.isFinite(activeSources)) {
    if (activeSources < 2) {
      return "low";
    }

    if (activeSources < 4) {
      return "medium";
    }

    return "high";
  }

  return "medium";
}

function normalizeAggregateRecord(input) {
  if (!input || typeof input !== "object") {
    return null;
  }

  const symbol = String(input.symbol || "").trim().toUpperCase();

  if (!symbol) {
    return null;
  }

  const updatedAtRaw = toOptionalFiniteNumber(input.updatedAt);
  const updatedAt = Number.isFinite(updatedAtRaw) ? updatedAtRaw : Date.now();
  const exchanges = Array.isArray(input.exchanges)
    ? input.exchanges.map((item) => String(item || "").trim().toLowerCase()).filter(Boolean)
    : [];
  const activeSources = Math.max(0, Math.trunc(toFiniteNumber(input.activeSources, exchanges.length)));
  const staleSources = Math.max(0, Math.trunc(toFiniteNumber(input.staleSources, 0)));
  const quality = resolveAggregateQuality(input.quality, activeSources);
  const ageMsRaw = toOptionalFiniteNumber(input.ageMs);
  const ageMs = Number.isFinite(ageMsRaw)
    ? Math.max(0, Math.trunc(ageMsRaw))
    : Math.max(0, Date.now() - updatedAt);
  const staleAfterMs = normalizeTickStaleAfterMs(input.staleAfterMs, state.tickStaleAfterMs);

  return {
    ...input,
    symbol,
    updatedAt,
    exchanges,
    activeSources,
    staleSources,
    quality,
    ageMs,
    staleAfterMs
  };
}

function getTickAgeMs(tick, nowTs = Date.now()) {
  const ageMsRaw = toOptionalFiniteNumber(tick?.ageMs);

  if (Number.isFinite(ageMsRaw) && ageMsRaw >= 0) {
    return Math.trunc(ageMsRaw);
  }

  const tsIngested = toOptionalFiniteNumber(tick?.tsIngested);

  if (!Number.isFinite(tsIngested)) {
    return Number.NaN;
  }

  return Math.max(0, Math.trunc(nowTs - tsIngested));
}

function isTickStale(tick, nowTs = Date.now()) {
  if (tick && typeof tick.isStale === "boolean") {
    return tick.isStale;
  }

  const ageMs = getTickAgeMs(tick, nowTs);

  if (!Number.isFinite(ageMs)) {
    return false;
  }

  const staleAfterMs = normalizeTickStaleAfterMs(tick?.staleAfterMs, state.tickStaleAfterMs);
  return ageMs > staleAfterMs;
}

function formatAgeShort(ageMsInput) {
  const ageMs = Number(ageMsInput);

  if (!Number.isFinite(ageMs) || ageMs < 0) {
    return "-";
  }

  const totalSeconds = Math.max(0, Math.floor(ageMs / 1000));

  if (totalSeconds < 60) {
    return `${totalSeconds}s`;
  }

  const totalMinutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;

  if (totalMinutes < 60) {
    return `${totalMinutes}m ${seconds}s`;
  }

  const hours = Math.floor(totalMinutes / 60);
  const minutes = totalMinutes % 60;
  return `${hours}h ${minutes}m`;
}
function normalizeExchangeHealthRecord(input) {
  if (!input || typeof input !== "object") {
    return null;
  }

  const exchange = String(input.exchange || "").trim().toLowerCase();

  if (!exchange) {
    return null;
  }

  const statusRaw = String(input.status || "").trim().toLowerCase();
  const status = statusRaw === "online" || statusRaw === "degraded" || statusRaw === "offline"
    ? statusRaw
    : "offline";

  const qualityScoreRaw = toOptionalFiniteNumber(input.qualityScore);
  const qualityScore = Number.isFinite(qualityScoreRaw)
    ? Math.max(0, Math.min(100, Math.round(qualityScoreRaw)))
    : Number.NaN;

  return {
    exchange,
    status,
    qualityScore,
    lastSuccessAt: toOptionalFiniteNumber(input.lastSuccessAt),
    lastErrorAt: toOptionalFiniteNumber(input.lastErrorAt),
    averageLatencyMs: toOptionalFiniteNumber(input.averageLatencyMs),
    errorCount: Math.max(0, Math.trunc(toFiniteNumber(input.errorCount, 0)))
  };
}

function setExchangeHealthData(items) {
  state.exchangeHealthById.clear();

  if (!Array.isArray(items)) {
    return;
  }

  for (const item of items) {
    const record = normalizeExchangeHealthRecord(item);

    if (!record) {
      continue;
    }

    state.exchangeHealthById.set(record.exchange, record);
  }
}

function getAggregateRowsSorted() {
  const rows = Array.from(state.aggregatesBySymbol.values());
  const query = state.searchQuery.trim().toLowerCase();

  const filtered = query
    ? rows.filter((row) => {
        const base = getBaseSymbol(row.symbol).toLowerCase();
        const name = getDisplayName(row.symbol).toLowerCase();
        const symbolPair = formatSymbolPair(row.symbol).toLowerCase();

        return (
          row.symbol.toLowerCase().includes(query) ||
          symbolPair.includes(query) ||
          base.includes(query) ||
          name.includes(query)
        );
      })
    : rows;

  return filtered.sort((a, b) => Number(b.midPrice ?? 0) - Number(a.midPrice ?? 0));
}

function pushLivePoint(symbol, midPrice, ts) {
  if (!Number.isFinite(midPrice)) {
    return;
  }

  let series = state.liveSeriesBySymbol.get(symbol);

  if (!series) {
    series = [];
    state.liveSeriesBySymbol.set(symbol, series);
  }

  const nextPoint = {
    ts: Number.isFinite(ts) ? ts : Date.now(),
    value: Number(midPrice)
  };

  const last = series[series.length - 1];

  if (last && last.ts === nextPoint.ts && last.value === nextPoint.value) {
    return;
  }

  series.push(nextPoint);

  if (series.length > 260) {
    series.splice(0, series.length - 260);
  }
}

function getSeriesForSymbol(symbol) {
  if (!symbol) {
    return [];
  }

  const live = state.liveSeriesBySymbol.get(symbol) || [];

  if (live.length >= 3) {
    return live;
  }

  const history = state.historyBySymbol.get(symbol) || [];

  return history
    .slice()
    .reverse()
    .map((row, idx) => ({ ts: Date.parse(row.createdAt) || Date.now() + idx, value: Number(row.midPrice) }))
    .filter((point) => Number.isFinite(point.value));
}

function getSeriesForSelectedSymbol() {
  return getSeriesForSymbol(state.selectedSymbol);
}

function getHistoryValuePrecision(value) {
  const numeric = Math.abs(Number(value));

  if (!Number.isFinite(numeric)) {
    return 4;
  }

  if (numeric >= 100) {
    return 2;
  }

  if (numeric >= 1) {
    return 4;
  }

  return 6;
}

function formatHistoryExchangeSummary(exchanges, maxVisible = 4) {
  if (!Array.isArray(exchanges) || !exchanges.length) {
    return "-";
  }

  const normalized = Array.from(
    new Set(
      exchanges
        .map((item) => getExchangeInfo(item).name)
        .map((item) => String(item || "").trim())
        .filter(Boolean)
    )
  );

  if (!normalized.length) {
    return "-";
  }

  const visible = normalized.slice(0, Math.max(1, maxVisible));
  const hiddenCount = Math.max(0, normalized.length - visible.length);

  return hiddenCount > 0 ? `${visible.join(", ")} +${hiddenCount}` : visible.join(", ");
}

function compactHistoryRows(rows, limit = 12) {
  if (!Array.isArray(rows) || !rows.length) {
    return [];
  }

  const normalizedRows = rows.filter(Boolean);

  if (normalizedRows.length <= limit) {
    return normalizedRows;
  }

  const sampledRows = [];
  const seenIds = new Set();
  const step = (normalizedRows.length - 1) / Math.max(limit - 1, 1);

  for (let index = 0; index < limit; index += 1) {
    const candidate = normalizedRows[Math.round(index * step)] || normalizedRows[normalizedRows.length - 1];

    if (!candidate || seenIds.has(candidate.id)) {
      continue;
    }

    seenIds.add(candidate.id);
    sampledRows.push(candidate);
  }

  return sampledRows.length ? sampledRows : normalizedRows.slice(0, limit);
}

function getRenderableHistoryForSymbol(symbol, limit = 40) {
  if (!symbol) {
    return [];
  }

  const persistedHistory = state.historyBySymbol.get(symbol) || [];
  const targetCount = Math.max(1, Math.min(limit, 12));

  if (persistedHistory.length) {
    return compactHistoryRows(persistedHistory, targetCount);
  }

  const aggregate = state.aggregatesBySymbol.get(symbol);
  const liveSeries = state.liveSeriesBySymbol.get(symbol) || [];

  if (!aggregate || !liveSeries.length) {
    return [];
  }

  const exchanges = Array.isArray(aggregate.exchanges)
    ? aggregate.exchanges.map((item) => String(item || "").trim().toLowerCase()).filter(Boolean)
    : [];
  const spread = toOptionalFiniteNumber(aggregate.spread);
  const rows = [];
  let lastValueKey = "";
  let lastSecondBucket = Number.NaN;

  for (let index = liveSeries.length - 1; index >= 0; index -= 1) {
    const point = liveSeries[index];
    const pointTs = Number.isFinite(point?.ts) ? Number(point.ts) : Date.now();
    const pointValue = Number(point?.value);

    if (!Number.isFinite(pointValue)) {
      continue;
    }

    const valueKey = pointValue.toFixed(getHistoryValuePrecision(pointValue));
    const secondBucket = Math.floor(pointTs / 1000);

    if (valueKey === lastValueKey || secondBucket === lastSecondBucket) {
      continue;
    }

    rows.push({
      id: `live-${symbol}-${pointTs}-${rows.length}`,
      symbol,
      bestBid: toOptionalFiniteNumber(aggregate.bestBid),
      bestAsk: toOptionalFiniteNumber(aggregate.bestAsk),
      midPrice: pointValue,
      spread: Number.isFinite(spread) ? spread : null,
      exchanges,
      updatedAt: pointTs,
      createdAt: new Date(pointTs).toISOString(),
      isLiveFallback: true
    });

    lastValueKey = valueKey;
    lastSecondBucket = secondBucket;

    if (rows.length >= Math.max(1, limit)) {
      break;
    }
  }

  if (rows.length > targetCount) {
    return compactHistoryRows(rows, targetCount);
  }

  return rows.length
    ? rows
    : liveSeries
      .slice(-Math.max(1, limit))
      .reverse()
      .map((point, index) => {
        const pointTs = Number.isFinite(point?.ts) ? Number(point.ts) : Date.now();
        const pointValue = Number(point?.value);

        return {
          id: `live-${symbol}-${pointTs}-${index}`,
        symbol,
        bestBid: toOptionalFiniteNumber(aggregate.bestBid),
        bestAsk: toOptionalFiniteNumber(aggregate.bestAsk),
        midPrice: Number.isFinite(pointValue) ? pointValue : toOptionalFiniteNumber(aggregate.midPrice),
        spread: Number.isFinite(spread) ? spread : null,
        exchanges,
        updatedAt: pointTs,
        createdAt: new Date(pointTs).toISOString(),
        isLiveFallback: true
        };
      })
      .filter((row) => Number.isFinite(Number(row.midPrice)));
}

function getFallbackLimitByRange(rangeMs, total) {
  const ms = Number(rangeMs);

  if (!Number.isFinite(ms) || ms <= 0) {
    return Math.min(total, 220);
  }

  if (ms <= 5 * 60 * 1000) {
    return Math.min(total, 30);
  }

  if (ms <= 15 * 60 * 1000) {
    return Math.min(total, 70);
  }

  if (ms <= 60 * 60 * 1000) {
    return Math.min(total, 120);
  }

  if (ms <= 6 * 60 * 60 * 1000) {
    return Math.min(total, 180);
  }

  return Math.min(total, 240);
}

function filterSeriesByRange(series, rangeMs) {
  if (!Array.isArray(series) || !series.length) {
    return [];
  }

  const ms = Number(rangeMs);

  if (!Number.isFinite(ms) || ms <= 0) {
    return series;
  }

  const endTs = Number(series[series.length - 1]?.ts) || Date.now();
  const startTs = endTs - ms;
  const filteredByTime = series.filter((point) => Number(point.ts) >= startTs);

  if (filteredByTime.length >= 3) {
    return filteredByTime;
  }

  const fallbackLimit = getFallbackLimitByRange(ms, series.length);
  const fallback = series.slice(Math.max(0, series.length - fallbackLimit));

  return fallback.length >= 2 ? fallback : series;
}

function drawLineChart(canvas, series) {
  const ctx = canvas.getContext("2d");

  if (!ctx) {
    return;
  }

  const width = canvas.width;
  const height = canvas.height;
  ctx.clearRect(0, 0, width, height);

  if (!series.length) {
    ctx.fillStyle = getComputedStyle(refs.root).getPropertyValue("--muted");
    ctx.font = "14px Space Grotesk";
    ctx.fillText(t("common.notEnoughData"), 16, 24);
    return;
  }

  const values = series.map((point) => point.value);
  const min = Math.min(...values);
  const max = Math.max(...values);
  const range = Math.max(max - min, 1e-9);
  const padX = 16;
  const padY = 16;

  const lineColor = getComputedStyle(refs.root).getPropertyValue("--green").trim() || "#2bcf86";
  const axisColor = getComputedStyle(refs.root).getPropertyValue("--line").trim() || "#2b4774";

  ctx.strokeStyle = axisColor;
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(padX, height - padY);
  ctx.lineTo(width - padX, height - padY);
  ctx.stroke();

  ctx.beginPath();

  series.forEach((point, index) => {
    const x = padX + (index / Math.max(series.length - 1, 1)) * (width - padX * 2);
    const y = padY + (1 - (point.value - min) / range) * (height - padY * 2);

    if (index === 0) {
      ctx.moveTo(x, y);
    } else {
      ctx.lineTo(x, y);
    }
  });

  ctx.strokeStyle = lineColor;
  ctx.lineWidth = 2;
  ctx.stroke();

  const first = series[0]?.value;
  const last = series[series.length - 1]?.value;

  if (Number.isFinite(first) && Number.isFinite(last) && first > 0) {
    const deltaPct = ((last - first) / first) * 100;
    const sign = deltaPct >= 0 ? "+" : "";

    ctx.fillStyle =
      deltaPct >= 0 ? lineColor : (getComputedStyle(refs.root).getPropertyValue("--red").trim() || "#ff6f78");
    ctx.font = "600 12px Space Grotesk";
    ctx.fillText(`${sign}${deltaPct.toFixed(2)}%`, width - 88, 22);
  }
}

function renderSummary() {
  const rows = Array.from(state.aggregatesBySymbol.values());
  refs.metricSymbols.textContent = String(rows.length);

  const spreads = rows.map((row) => Number(row.spread)).filter((value) => Number.isFinite(value));

  const avgSpread = spreads.length
    ? spreads.reduce((acc, value) => acc + value, 0) / spreads.length
    : Number.NaN;

  refs.metricSpread.textContent = Number.isFinite(avgSpread) ? formatSpread(avgSpread) : "-";

  const totalVolumeBySymbol = new Map();
  const exchanges = new Set();

  for (const exchangeMap of state.latestTickBySymbolExchange.values()) {
    for (const tick of exchangeMap.values()) {
      exchanges.add(tick.exchange);
      const prev = totalVolumeBySymbol.get(tick.symbol) || 0;
      totalVolumeBySymbol.set(tick.symbol, Math.max(prev, Number(tick.volume24h || 0)));
    }
  }

  const totalVolumeUsd = Array.from(totalVolumeBySymbol.values()).reduce((acc, value) => acc + value, 0);
  refs.metricVolume.textContent = formatCurrency(totalVolumeUsd, true);

  const configuredCount = Array.isArray(state.configuredExchanges) ? state.configuredExchanges.length : 0;
  refs.metricExchanges.textContent = String(Math.max(exchanges.size, configuredCount));
}

function renderMarketTable() {
  const rows = getAggregateRowsSorted();
  const isGuest = !state.auth.user;
  const visibleRows = isGuest ? rows.slice(0, 6) : rows;

  if (!visibleRows.length) {
    refs.marketTableBody.innerHTML = `<tr><td colspan="10" class="loading">${t("common.noDataYet")}</td></tr>`;
    return;
  }

  const bodyRows = visibleRows
    .map((row, index) => {
      const isActive = row.symbol === state.selectedSymbol;
      const name = getDisplayName(row.symbol);
      const icon = getCoinIcon(row.symbol);
      const activeSources = Math.max(0, Math.trunc(toFiniteNumber(row.activeSources, Array.isArray(row.exchanges) ? row.exchanges.length : 0)));
      const staleSources = Math.max(0, Math.trunc(toFiniteNumber(row.staleSources, 0)));
      const totalSources = Math.max(activeSources + staleSources, activeSources);
      const quality = resolveAggregateQuality(row.quality, activeSources);
      const qualityLabel = t(`quality.${quality}`);
      const qualityMeta = totalSources > 0 ? `${activeSources}/${totalSources}` : "-";
      const actionLabel = isGuest ? t("guest.marketAction") : t("table.investNow");
      const actionClass = isGuest ? "marketActionBtn guest" : "marketActionBtn";

      return `
        <tr data-symbol="${row.symbol}" class="${isActive ? "active" : ""}">
          <td>${index + 1}</td>
          <td>
            <div class="assetCell">
              <img class="assetIcon" src="${icon}" alt="${name}" loading="eager" decoding="async" data-fallback-src="${getCoinFallbackIcon(row.symbol)}" onerror="this.onerror=null;this.src=this.dataset.fallbackSrc;" />
              <span>${name}</span>
            </div>
          </td>
          <td>${formatSymbolPair(row.symbol)}</td>
          <td>${formatCurrency(row.midPrice)}</td>
          <td>${formatCurrency(row.bestBid)}</td>
          <td>${formatCurrency(row.bestAsk)}</td>
          <td>${formatSpread(row.spread)}</td>
          <td>
            <div class="aggregateQualityCell">
              <span class="aggQualityBadge ${quality}">${qualityLabel}</span>
              <span class="qualityMeta">${qualityMeta}</span>
            </div>
          </td>
          <td>${formatClock(row.updatedAt)}</td>
          <td>
            <div class="marketActionCell">
              <button class="${actionClass}" type="button" data-market-action="invest" data-symbol="${row.symbol}">${actionLabel}</button>
            </div>
          </td>
        </tr>
      `;
    })
    .join("");

  const teaserRow =
    isGuest && rows.length > visibleRows.length
      ? `
        <tr class="guestPreviewRow">
          <td colspan="10">
            <div class="guestPreviewNote">
              <strong>${t("guest.moreAssets", { count: rows.length - visibleRows.length })}</strong>
              <button class="marketActionBtn guest" type="button" data-market-action="guest-unlock">${t("guest.bannerAction")}</button>
            </div>
          </td>
        </tr>
      `
      : "";

  refs.marketTableBody.innerHTML = bodyRows + teaserRow;

  refs.marketTableBody.querySelectorAll("tr[data-symbol]").forEach((tr) => {
    tr.addEventListener("click", () => {
      state.selectedSymbol = tr.getAttribute("data-symbol");
      state.marketView.symbol = state.selectedSymbol || state.marketView.symbol;
      localStorage.setItem(CHART_SYMBOL_KEY, state.marketView.symbol || "");
      renderMarketTable();
      void refreshSelectedHistory();
      renderDetails();
      renderMarketTab();
    });
  });

  refs.marketTableBody.querySelectorAll("[data-market-action='invest']").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.stopPropagation();
      openInvestmentFlow(button.getAttribute("data-symbol") || "");
    });
  });

  refs.marketTableBody.querySelectorAll("[data-market-action='guest-unlock']").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.stopPropagation();
      openRegistrationPrompt();
    });
  });
}

function renderDetails() {
  if (!state.selectedSymbol) {
    refs.detailTitle.textContent = "- / USDT";
    refs.detailSubtitle.textContent = t("common.selectRow");
    setImageSourceWithFallback(refs.detailIcon, LOCAL_COIN_ICONS.DEFAULT, LOCAL_COIN_ICONS.DEFAULT);
    refs.detailPrice.textContent = "-";
    refs.detailDelta.textContent = "-";
    refs.detailDelta.className = "delta";
    refs.factBid.textContent = "-";
    refs.factAsk.textContent = "-";
    refs.factSpread.textContent = "-";
    refs.factExchanges.textContent = "-";
    refs.factHistoryCount.textContent = "-";
    drawLineChart(refs.sparkline, []);
    renderHistoryViewer();
    return;
  }

  const aggregate = state.aggregatesBySymbol.get(state.selectedSymbol);

  if (!aggregate) {
    renderHistoryViewer();
    return;
  }

  const history = getRenderableHistoryForSymbol(state.selectedSymbol);
  const series = getSeriesForSelectedSymbol();

  refs.detailTitle.textContent = formatSymbolPair(state.selectedSymbol);
  refs.detailSubtitle.textContent = `${t("table.updated")}: ${formatClock(aggregate.updatedAt)}`;
  setImageSourceWithFallback(refs.detailIcon, getCoinIcon(state.selectedSymbol), getCoinFallbackIcon(state.selectedSymbol));
  refs.detailPrice.textContent = formatCurrency(aggregate.midPrice);

  let deltaText = "-";
  let deltaClass = "delta";

  if (series.length >= 2) {
    const first = series[0].value;
    const last = series[series.length - 1].value;

    if (Number.isFinite(first) && Number.isFinite(last) && first > 0) {
      const pct = ((last - first) / first) * 100;
      const sign = pct >= 0 ? "+" : "";
      deltaText = `${sign}${pct.toFixed(2)}%`;
      deltaClass = pct >= 0 ? "delta up" : "delta down";
    }
  }

  refs.detailDelta.textContent = deltaText;
  refs.detailDelta.className = deltaClass;

  refs.factBid.textContent = formatCurrency(aggregate.bestBid);
  refs.factAsk.textContent = formatCurrency(aggregate.bestAsk);
  refs.factSpread.textContent = formatSpread(aggregate.spread);
  refs.factExchanges.textContent = (aggregate.exchanges || []).join(", ") || "-";
  refs.factHistoryCount.textContent = String(history.length);

  drawLineChart(refs.sparkline, series);
  renderHistoryViewer();
}

function renderHistoryViewer() {
  if (!refs.historyTableBody) {
    return;
  }

  if (!state.selectedSymbol) {
    if (refs.historyPanelHint) {
      refs.historyPanelHint.textContent = t("history.viewerHint");
    }

    refs.historyTableBody.innerHTML = `<tr><td colspan="4" class="loading">${t("common.selectRow")}</td></tr>`;
    return;
  }

  const history = getRenderableHistoryForSymbol(state.selectedSymbol);

  if (refs.historyPanelHint) {
    refs.historyPanelHint.textContent = history.length
      ? t("history.hintWithCount", {
          symbol: formatSymbolPair(state.selectedSymbol),
          count: history.length
        })
      : t("history.viewerHint");
  }

  if (!history.length) {
    refs.historyTableBody.innerHTML = `<tr><td colspan="4" class="loading">${t("history.noData")}</td></tr>`;
    return;
  }

  refs.historyTableBody.innerHTML = history
    .slice(0, 12)
    .map((row) => {
      const createdTs = Date.parse(row.createdAt);
      const createdLabel = Number.isFinite(createdTs)
        ? (row.isLiveFallback ? formatClock(createdTs) : formatDateTime(createdTs))
        : "-";
      const exchanges = formatHistoryExchangeSummary(row.exchanges, 4);

      return `
        <tr>
          <td>
            <div class="historyTimeCell">
              <span>${createdLabel}</span>
            </div>
          </td>
          <td>${formatCurrency(row.midPrice)}</td>
          <td>${formatSpread(row.spread)}</td>
          <td><span class="historyExchangesCell">${exchanges}</span></td>
        </tr>
      `;
    })
    .join("");
}
function renderLeaders() {
  const results = [];

  for (const [symbol, series] of state.liveSeriesBySymbol.entries()) {
    if (!series || series.length < 2) {
      continue;
    }

    const first = series[0].value;
    const last = series[series.length - 1].value;

    if (!Number.isFinite(first) || !Number.isFinite(last) || first <= 0) {
      continue;
    }

    results.push({ symbol, pct: ((last - first) / first) * 100 });
  }

  results.sort((a, b) => b.pct - a.pct);
  const top = results.slice(0, 5);

  refs.leadersList.innerHTML = top.length
    ? top
        .map((row) => {
          const sign = row.pct >= 0 ? "+" : "";
          return `<li>${formatSymbolPair(row.symbol)}: ${sign}${row.pct.toFixed(2)}%</li>`;
        })
        .join("")
    : `<li>${t("leaders.empty")}</li>`;
}

function renderMarketTab() {
  const rows = Array.from(state.aggregatesBySymbol.values()).sort((a, b) => Number(b.midPrice ?? 0) - Number(a.midPrice ?? 0));

  if (!state.marketView.rangeId || !CHART_RANGE_OPTIONS.some((item) => item.id === state.marketView.rangeId)) {
    state.marketView.rangeId = "15m";
  }

  if (!state.marketView.symbol || !state.aggregatesBySymbol.has(state.marketView.symbol)) {
    state.marketView.symbol = state.selectedSymbol || rows[0]?.symbol || "";
  }

  const symbolOptions = rows.map((row) => row.symbol);

  refs.marketSymbolSelect.innerHTML = symbolOptions
    .map((symbol) => `<option value="${symbol}">${formatSymbolPair(symbol)}</option>`)
    .join("");

  if (!symbolOptions.includes(state.marketView.symbol) && symbolOptions.length) {
    state.marketView.symbol = symbolOptions[0];
  }

  refs.marketSymbolSelect.value = state.marketView.symbol;

  refs.marketRangeSelect.innerHTML = CHART_RANGE_OPTIONS
    .map((item) => `<option value="${item.id}">${t(`market.range.${item.id}`)}</option>`)
    .join("");
  refs.marketRangeSelect.value = state.marketView.rangeId;

  const movers = rows
    .map((row) => {
      const series = state.liveSeriesBySymbol.get(row.symbol) || [];

      if (series.length < 2) {
        return null;
      }

      const first = series[0].value;
      const last = series[series.length - 1].value;

      if (!Number.isFinite(first) || !Number.isFinite(last) || first <= 0) {
        return null;
      }

      const pct = ((last - first) / first) * 100;

      return {
        symbol: row.symbol,
        price: row.midPrice,
        pct,
        exchanges: (row.exchanges || []).length
      };
    })
    .filter((row) => row !== null)
    .sort((a, b) => Math.abs(b.pct) - Math.abs(a.pct))
    .slice(0, 12);

  refs.moversTableBody.innerHTML = movers.length
    ? movers
        .map((row) => {
          const sign = row.pct >= 0 ? "+" : "";
          return `
            <tr>
              <td>${formatSymbolPair(row.symbol)}</td>
              <td>${formatCurrency(row.price)}</td>
              <td class="${row.pct >= 0 ? "delta up" : "delta down"}">${sign}${row.pct.toFixed(2)}%</td>
              <td>${row.exchanges}</td>
            </tr>
          `;
        })
        .join("")
    : `<tr><td colspan="4" class="loading">${t("market.noLiveData")}</td></tr>`;

  const rangeMs = CHART_RANGE_OPTIONS.find((item) => item.id === state.marketView.rangeId)?.ms;
  const series = getSeriesForSymbol(state.marketView.symbol);
  drawLineChart(refs.marketChart, filterSeriesByRange(series, rangeMs));
}

function buildExchangeData() {
  const rows = [];
  const exchangeStatMap = new Map();
  const nowTs = Date.now();

  for (const [symbol, perExchange] of state.latestTickBySymbolExchange.entries()) {
    for (const [exchange, tick] of perExchange.entries()) {
      const bid = Number(tick.bid);
      const ask = Number(tick.ask);
      const spread = bid > 0 && ask > 0 ? ask - bid : Number.NaN;
      const volume24h = Number(tick.volume24h);
      const tsIngested = Number(tick.tsIngested);
      const ageMs = getTickAgeMs(tick, nowTs);
      const stale = isTickStale(tick, nowTs);

      rows.push({
        exchange,
        symbol,
        lastPrice: Number(tick.lastPrice),
        bid,
        ask,
        spread,
        volume24h,
        source: tick.source,
        tsIngested,
        ageMs,
        isStale: stale
      });

      const prev = exchangeStatMap.get(exchange) || {
        symbols: new Set(),
        count: 0,
        latestTs: 0,
        volume24h: 0,
        spreadSum: 0,
        spreadCount: 0
      };

      prev.symbols.add(symbol);
      prev.count += 1;
      prev.latestTs = Math.max(prev.latestTs, tsIngested || 0);
      prev.volume24h += Number.isFinite(volume24h) && volume24h > 0 ? volume24h : 0;

      if (Number.isFinite(spread)) {
        prev.spreadSum += spread;
        prev.spreadCount += 1;
      }

      exchangeStatMap.set(exchange, prev);
    }
  }

  rows.sort((a, b) => {
    const byExchange = String(a.exchange || "").localeCompare(String(b.exchange || ""));

    if (byExchange !== 0) {
      return byExchange;
    }

    return String(a.symbol || "").localeCompare(String(b.symbol || ""));
  });

  return {
    rows,
    exchangeStatMap
  };
}

function renderExchangeDetail(exchangeStatsRows, totalVolume, totalTicks) {
  if (state.selectedExchange === "all") {
    refs.exchangeDetail.innerHTML = `
      <h3 class="exchangeDetailTitle">${t("exchanges.all")}</h3>
      <div class="exchangeDetailLabel">${t("exchanges.allHint")}</div>
    `;

    refs.exchangePanelHint.textContent = t("exchanges.subtitle");
    return;
  }

  const row = exchangeStatsRows.find((item) => item.exchange === state.selectedExchange);

  if (!row) {
    refs.exchangeDetail.innerHTML = `<div class="exchangeDetailLabel">${t("exchanges.noData")}</div>`;
    refs.exchangePanelHint.textContent = t("exchanges.subtitle");
    return;
  }

  const share = totalVolume > 0 ? (row.volume24h / totalVolume) * 100 : (row.ticks / Math.max(totalTicks, 1)) * 100;
  const avgSpread = row.spreadCount > 0 ? row.spreadSum / row.spreadCount : Number.NaN;
  const meta = getExchangeInfo(row.exchange);

  refs.exchangeDetail.innerHTML = `
    <h3 class="exchangeDetailTitle">${t("exchanges.detailTitle")}: ${meta.name}</h3>
    <ul class="exchangeDetailList">
      <li><span class="exchangeDetailLabel">${t("exchanges.detailShare")}</span><strong>${share.toFixed(2)}%</strong></li>
      <li><span class="exchangeDetailLabel">${t("exchanges.detailSymbols")}</span><strong>${row.symbols}</strong></li>
      <li><span class="exchangeDetailLabel">${t("exchanges.detailTicks")}</span><strong>${formatCompactNumber(row.ticks)}</strong></li>
      <li><span class="exchangeDetailLabel">${t("exchanges.detailVolume")}</span><strong>${formatCurrency(row.volume24h, true)}</strong></li>
      <li><span class="exchangeDetailLabel">${t("exchanges.detailAvgSpread")}</span><strong>${Number.isFinite(avgSpread) ? formatSpread(avgSpread) : "-"}</strong></li>
      <li><span class="exchangeDetailLabel">${t("exchanges.detailUpdated")}</span><strong>${formatDateTime(row.latestTs)}</strong></li>
    </ul>
  `;

  refs.exchangePanelHint.textContent = t("exchanges.selectedHint", { name: meta.name });
}

function renderExchangeHealthTable() {
  if (!refs.exchangeHealthBody) {
    return;
  }

  const ordered = [];
  const seen = new Set();
  const configured = Array.isArray(state.configuredExchanges) ? state.configuredExchanges : [];

  for (const exchange of configured) {
    const normalized = String(exchange || "").trim().toLowerCase();

    if (!normalized || seen.has(normalized)) {
      continue;
    }

    seen.add(normalized);
    ordered.push(normalized);
  }

  for (const exchange of state.exchangeHealthById.keys()) {
    if (!seen.has(exchange)) {
      seen.add(exchange);
      ordered.push(exchange);
    }
  }

  if (!ordered.length) {
    refs.exchangeHealthBody.innerHTML =
      `<tr><td colspan="7" class="loading">${t("exchanges.health.noData")}</td></tr>`;
    return;
  }

  refs.exchangeHealthBody.innerHTML = ordered
    .map((exchange) => {
      const record = state.exchangeHealthById.get(exchange);
      const meta = getExchangeInfo(exchange);
      const status = record?.status || "offline";
      const statusKey = `exchanges.health.status.${status}`;
      const statusLabel = t(statusKey);
      const qualityScore = Number.isFinite(record?.qualityScore)
        ? Math.max(0, Math.min(100, Math.round(record.qualityScore)))
        : Number.NaN;
      const qualityScoreLabel = Number.isFinite(qualityScore) ? `${qualityScore}%` : "-";
      const qualityScoreClass = !Number.isFinite(qualityScore)
        ? "unknown"
        : qualityScore >= 80
          ? "good"
          : qualityScore >= 55
            ? "medium"
            : "poor";
      const lastSuccess = Number.isFinite(record?.lastSuccessAt) ? formatDateTime(record.lastSuccessAt) : "-";
      const avgLatency = Number.isFinite(record?.averageLatencyMs)
        ? `${record.averageLatencyMs.toFixed(0)} ms`
        : "-";
      const errors = Number.isFinite(record?.errorCount) ? String(record.errorCount) : "0";
      const lastError = Number.isFinite(record?.lastErrorAt) ? formatDateTime(record.lastErrorAt) : "-";

      return `
        <tr>
          <td>
            <div class="exchangeCell">
              <span class="exchangeBadge" aria-label="${meta.name}">${getExchangeBadgeText(exchange)}</span>
              <span>${meta.name}</span>
            </div>
          </td>
          <td><span class="healthStatus ${status}">${statusLabel}</span></td>
          <td><span class="qualityScore ${qualityScoreClass}">${qualityScoreLabel}</span></td>
          <td>${lastSuccess}</td>
          <td>${avgLatency}</td>
          <td>${errors}</td>
          <td>${lastError}</td>
        </tr>
      `;
    })
    .join("");
}

function renderExchangesTab() {
  const { rows, exchangeStatMap } = buildExchangeData();

  const exchangeNames = state.configuredExchanges.length
    ? state.configuredExchanges
    : Array.from(exchangeStatMap.keys());

  if (state.selectedExchange !== "all" && !exchangeNames.includes(state.selectedExchange)) {
    state.selectedExchange = "all";
  }
  if (refs.exchangeSearchInput && refs.exchangeSearchInput.value !== state.exchangeSearchQuery) {
    refs.exchangeSearchInput.value = state.exchangeSearchQuery;
  }

  if (refs.exchangeSourceFilter) {
    refs.exchangeSourceFilter.value = normalizeExchangeSourceFilter(state.exchangeSourceFilter);
  }

  if (refs.exchangeSortSelect) {
    refs.exchangeSortSelect.value = normalizeExchangeSortKey(state.exchangeSortKey);
  }

  const sourceFilter = normalizeExchangeSourceFilter(state.exchangeSourceFilter);
  const sortKey = normalizeExchangeSortKey(state.exchangeSortKey);
  const searchQuery = String(state.exchangeSearchQuery || "").trim().toLowerCase();

  const filteredRows = rows
    .filter((row) => state.selectedExchange === "all" || row.exchange === state.selectedExchange)
    .filter((row) => sourceFilter === "all" || String(row.source || "").trim().toLowerCase() === sourceFilter)
    .filter((row) => {
      if (!searchQuery) {
        return true;
      }

      const exchangeName = getExchangeInfo(row.exchange).name.toLowerCase();
      const exchangeId = String(row.exchange || "").toLowerCase();
      const symbol = String(row.symbol || "").toLowerCase();
      const pair = formatSymbolPair(row.symbol).toLowerCase();

      return exchangeName.includes(searchQuery) || exchangeId.includes(searchQuery) || symbol.includes(searchQuery) || pair.includes(searchQuery);
    })
    .sort((a, b) => compareExchangeRows(a, b, sortKey));

  const noDataKey = rows.length > 0 ? "exchanges.tableNoDataFiltered" : "exchanges.tableNoData";

  refs.exchangeTableBody.innerHTML = filteredRows.length
    ? filteredRows
        .map((row) => {
          const meta = getExchangeInfo(row.exchange);
          const sourceLabel = String(row.source || "-").toUpperCase();
          const sourceHtml = row.isStale
            ? `<div class="tickSourceCell"><span class="tickSourceTag">${sourceLabel}</span><span class="staleTickBadge">${t("ticks.stale")}</span></div>`
            : `<span class="tickSourceTag">${sourceLabel}</span>`;
          const updatedLabel = Number.isFinite(row.ageMs)
            ? `${formatClock(row.tsIngested)} | ${formatAgeShort(row.ageMs)}`
            : formatClock(row.tsIngested);

          return `
            <tr>
              <td>
                <div class="exchangeCell">
                  <span class="exchangeBadge" aria-label="${meta.name}">${getExchangeBadgeText(row.exchange)}</span>
                  <span>${meta.name}</span>
                </div>
              </td>
              <td>${formatSymbolPair(row.symbol)}</td>
              <td>${formatCurrency(row.lastPrice)}</td>
              <td>${formatCurrency(row.bid)}</td>
              <td>${formatCurrency(row.ask)}</td>
              <td>${formatCurrency(row.volume24h, true)}</td>
              <td>${sourceHtml}</td>
              <td>${updatedLabel}</td>
            </tr>
          `;
        })
        .join("")
    : `<tr><td colspan="8" class="loading">${t(noDataKey)}</td></tr>`;

  const exchangeStatsRows = exchangeNames.map((name) => {
    const value = exchangeStatMap.get(name) || {
      symbols: new Set(),
      count: 0,
      latestTs: 0,
      volume24h: 0,
      spreadSum: 0,
      spreadCount: 0
    };

    return {
      exchange: name,
      symbols: value.symbols.size,
      ticks: value.count,
      latestTs: value.latestTs,
      volume24h: value.volume24h,
      spreadSum: value.spreadSum,
      spreadCount: value.spreadCount
    };
  });

  const exchangeOrder = new Map(exchangeNames.map((name, index) => [name, index]));

  exchangeStatsRows.sort((a, b) => {
    const orderA = exchangeOrder.get(a.exchange) ?? Number.MAX_SAFE_INTEGER;
    const orderB = exchangeOrder.get(b.exchange) ?? Number.MAX_SAFE_INTEGER;

    if (orderA !== orderB) {
      return orderA - orderB;
    }

    return a.exchange.localeCompare(b.exchange);
  });

  const totalVolume = exchangeStatsRows.reduce((acc, row) => acc + row.volume24h, 0);
  const totalTicks = exchangeStatsRows.reduce((acc, row) => acc + row.ticks, 0);

  const allCard = `
    <li class="exchangeStatItem ${state.selectedExchange === "all" ? "active" : ""}" data-exchange="all">
      <div class="exchangeStatTop">
        <strong>${t("exchanges.all")}</strong>
        <span>100%</span>
      </div>
      <div class="exchangeStatMeta">${t("exchanges.allHint")}</div>
      <div class="exchangeBar"><span class="exchangeBarFill" style="width: 100%"></span></div>
    </li>
  `;

  const exchangeCards = exchangeStatsRows
    .map((row) => {
      const meta = getExchangeInfo(row.exchange);
      const share = totalVolume > 0 ? (row.volume24h / totalVolume) * 100 : (row.ticks / Math.max(totalTicks, 1)) * 100;
      const shareLabel = `${share.toFixed(2)}%`;
      const barWidth = Math.max(2, Math.min(100, share));

      return `
        <li class="exchangeStatItem ${state.selectedExchange === row.exchange ? "active" : ""}" data-exchange="${row.exchange}">
          <div class="exchangeStatTop">
            <div class="exchangeCell">
              <span class="exchangeBadge" aria-label="${meta.name}">${getExchangeBadgeText(row.exchange)}</span>
              <strong>${meta.name}</strong>
            </div>
            <span>${shareLabel}</span>
          </div>
          <div class="exchangeStatMeta">${row.symbols} ${t("exchanges.meta.symbols")}, ${formatCompactNumber(row.ticks)} ${t("exchanges.meta.ticks")}, ${t("table.updated").toLowerCase()} ${formatClock(row.latestTs)}</div>
          <div class="exchangeBar"><span class="exchangeBarFill" style="width: ${barWidth}%"></span></div>
        </li>
      `;
    })
    .join("");

  refs.exchangeStats.innerHTML = exchangeStatsRows.length ? allCard + exchangeCards : `<li>${t("exchanges.noData")}</li>`;

  refs.exchangeStats.querySelectorAll(".exchangeStatItem[data-exchange]").forEach((item) => {
    item.addEventListener("click", () => {
      const exchange = item.getAttribute("data-exchange") || "all";
      state.selectedExchange = exchange;
      renderExchangesTab();
    });
  });

  renderExchangeDetail(exchangeStatsRows, totalVolume, totalTicks);
  renderExchangeHealthTable();
}

function renderAuthState() {
  if (!refs.profileBtn || !refs.adminBtn || !refs.profileChipName || !refs.profileChipAvatar || !refs.authActionBtn) {
    return;
  }

  if (!state.auth.user) {
    refs.profileBtn.classList.add("hidden");
    refs.adminBtn.classList.add("hidden");
    refs.profileChipName.textContent = t("auth.status.openProfile");
    refs.profileChipAvatar.src = buildDefaultAvatarDataUrl("User");
    refs.authActionBtn.textContent = t("auth.actionOpen");
    if (refs.reportRecipientEmail) {
      refs.reportRecipientEmail.value = "";
    }
    renderProfileReportSummary();
    applyGuestExperience();
    return;
  }

  refs.profileBtn.classList.remove("hidden");
  refs.adminBtn.classList.toggle("hidden", !Boolean(state.auth.user.isOwner));
  refs.profileChipName.textContent = state.auth.user.displayName;
  refs.profileChipAvatar.src = getUserAvatarUrl(state.auth.user);
  refs.authActionBtn.textContent = t("auth.actionLogout");
  if (refs.reportRecipientEmail && !refs.reportRecipientEmail.value.trim()) {
    refs.reportRecipientEmail.value = state.auth.user.email || "";
  }
  renderProfileReportSummary();
  applyGuestExperience();
}

