function renderProfileModal() {
  if (
    !state.auth.user ||
    !refs.profileDisplayName ||
    !refs.profileEmail ||
    !refs.profileBalanceUsd ||
    !refs.profileBalanceBtc ||
    !refs.profileBalanceEth ||
    !refs.profileAvatarPreview
  ) {
    return;
  }

  const analytics = buildPortfolioAnalytics(state.auth.user);
  const investRows = getAggregateRowsSorted();
  const nextInvestSymbol =
    state.profileInvestSymbol && investRows.some((row) => row.symbol === state.profileInvestSymbol)
      ? state.profileInvestSymbol
      : state.selectedSymbol && investRows.some((row) => row.symbol === state.selectedSymbol)
        ? state.selectedSymbol
        : investRows[0]?.symbol || "";

  state.profileInvestSymbol = nextInvestSymbol;
  refs.profileDisplayName.value = state.auth.user.displayName;
  refs.profileEmail.value = state.auth.user.email;

  if (refs.ownerClaimSection) {
    refs.ownerClaimSection.classList.add("hidden");
  }
  refs.profileBalanceUsd.textContent = formatCurrency(state.auth.user.wallet.usd);
  refs.profileBalanceBtc.textContent = formatCryptoAmount(state.auth.user.wallet.btc, "BTC");
  refs.profileBalanceEth.textContent = formatCryptoAmount(state.auth.user.wallet.eth, "ETH");
  if (refs.profileAvailableCash) {
    refs.profileAvailableCash.textContent = formatCurrency(analytics.cashUsd);
  }
  if (refs.profilePortfolioValue) {
    refs.profilePortfolioValue.textContent = formatCurrency(analytics.portfolioValueUsd);
  }
  if (refs.profileTotalEquity) {
    refs.profileTotalEquity.textContent = formatCurrency(analytics.totalEquityUsd);
  }
  if (refs.profileOpenPositions) {
    refs.profileOpenPositions.textContent = String(analytics.positionsCount);
  }
  if (refs.profileInvestSymbol) {
    refs.profileInvestSymbol.innerHTML = investRows.length
      ? investRows
          .map((row) => `<option value="${row.symbol}">${getDisplayName(row.symbol)} В· ${formatSymbolPair(row.symbol)}</option>`)
          .join("")
      : `<option value="">${t("common.noData")}</option>`;
    refs.profileInvestSymbol.value = nextInvestSymbol;
  }
  refs.profileAvatarPreview.src = state.profileDraftAvatar || getUserAvatarUrl(state.auth.user);
  renderPortfolioPositions();
  renderProfileActivityHistory();
  renderProfileReportSummary();
  renderInvestmentDraftInfo();
}

