function renderAdminUsers() {
  if (!state.admin.users.length) {
    refs.adminUsersBody.innerHTML = `<tr><td colspan="7" class="loading">${t("admin.noUsers")}</td></tr>`;
    return;
  }

  refs.adminUsersBody.innerHTML = state.admin.users
    .map((user) => {
      const isBanned = Boolean(user.isBanned);
      const statusClass = isBanned ? "banned" : "active";
      const statusText = isBanned ? t("admin.statusBanned") : t("admin.statusActive");
      const actionText = isBanned ? t("admin.alreadyBanned") : t("admin.delete");

      return `
        <tr>
          <td>${user.id}</td>
          <td><img class="adminAvatar" src="${getUserAvatarUrl(user)}" alt="${user.displayName}" loading="lazy" /></td>
          <td>${user.displayName}</td>
          <td>${user.email}</td>
          <td><span class="statusPill ${statusClass}">${statusText}</span></td>
          <td>${new Date(user.createdAt).toLocaleString(getLocale())}</td>
          <td><button class="dangerBtn" type="button" data-admin-delete="${user.id}" ${isBanned ? "disabled" : ""}>${actionText}</button></td>
        </tr>
      `;
    })
    .join("");

  refs.adminUsersBody.querySelectorAll("button[data-admin-delete]").forEach((button) => {
    button.addEventListener("click", () => {
      const userId = button.getAttribute("data-admin-delete") || "";
      const user = state.admin.users.find((item) => item.id === userId);

      if (!user || user.isBanned) {
        return;
      }

      void deleteUserAsAdmin(user.id, user.displayName);
    });
  });
}

async function deleteUserAsAdmin(userId, displayName) {
  if (!state.auth.user || !state.auth.user.isOwner || !state.auth.token) {
    setAdminStatus(t("errors.forbidden"), true);
    return;
  }

  const confirmed = window.confirm(t("admin.confirmDelete", { name: displayName }));

  if (!confirmed) {
    return;
  }

  setAdminStatus(t("admin.deleting"));

  try {
    await fetchJson(`/api/v1/admin/users/${encodeURIComponent(userId)}`, {
      method: "DELETE",
      headers: {
        Authorization: `Bearer ${state.auth.token}`
      }
    });

    if (state.auth.user && state.auth.user.id === userId) {
      clearAuth();
      setAuthStatus(t("errors.userRemoved"), true);
      showAuthModal();
      return;
    }

    await loadAdminUsers();
    setAdminStatus(t("admin.deleted"));
  } catch (error) {
    setAdminStatus(localizeApiError(error.message || error), true);
  }
}

async function loadAdminUsers() {
  if (!state.auth.user || !state.auth.user.isOwner || !state.auth.token) {
    setAdminStatus(t("errors.forbidden"), true);
    refs.adminUsersBody.innerHTML = "<tr><td colspan=\"7\" class=\"loading\">" + t("errors.forbidden") + "</td></tr>";
    return;
  }

  setAdminStatus(t("admin.loading"));

  try {
    const payload = await fetchJson("/api/v1/admin/users?limit=500", {
      headers: {
        Authorization: `Bearer ${state.auth.token}`
      }
    });

    state.admin.users = payload.data || [];
    renderAdminUsers();
    setAdminStatus(t("admin.loaded", { count: state.admin.users.length }));
  } catch (error) {
    refs.adminUsersBody.innerHTML = "<tr><td colspan=\"7\" class=\"loading\">" + t("errors.forbidden") + "</td></tr>";
    setAdminStatus(localizeApiError(error.message || error), true);
  }
}

async function activateOwnerFromProfile(setupKey) {
  if (!state.auth.user || !state.auth.token) {
    throw new Error("Invalid or expired token");
  }

  return fetchJson("/api/v1/auth/owner/activate", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${state.auth.token}`
    },
    body: JSON.stringify({ setupKey })
  });
}

async function fetchJson(url, options = {}) {
  const response = await fetch(url, options);
  const body = await response.json().catch(() => ({}));

  if (!response.ok) {
    throw new Error(body.error || `HTTP ${response.status}`);
  }

  return body;
}

function populateCurrencySelect() {
  const available = Object.keys(state.fx.rates || {}).filter((code) => /^[A-Z]{3,8}$/.test(code));
  const set = new Set(available);
  const ordered = [
    ...PRIORITY_CURRENCIES.filter((code) => set.has(code)),
    ...available.filter((code) => !PRIORITY_CURRENCIES.includes(code)).sort()
  ];

  refs.currencySelect.innerHTML = ordered.map((code) => `<option value="${code}">${getCurrencyLabel(code)}</option>`).join("");

  if (!set.has(state.currency)) {
    state.currency = "USD";
  }

  refs.currencySelect.value = state.currency;
  refs.currencySelect.dataset.currency = state.currency.toLowerCase();
}

async function loadExchangeHealth() {
  try {
    const payload = await fetchJson("/api/v1/exchanges/status");
    setExchangeHealthData(payload.data || []);
    markUiDirty({ exchanges: true });
  } catch {
    // ignore health polling errors
  }
}

async function loadFxRates() {
  try {
    const payload = await fetchJson("/api/v1/fx/rates?base=USD");

    state.fx.base = payload.base || "USD";
    state.fx.rates = payload.rates || { USD: 1 };
    state.fx.source = payload.source || "unknown";
    state.fx.updatedAt = payload.updatedAt || "";
  } catch {
    state.fx.base = "USD";
    state.fx.rates = state.fx.rates && Object.keys(state.fx.rates).length ? state.fx.rates : { USD: 1 };
    state.fx.source = "local";
    state.fx.updatedAt = new Date().toISOString();
  }

  populateCurrencySelect();
}

async function tryRestoreProfile() {
  const savedToken = String(localStorage.getItem(LEGACY_AUTH_TOKEN_KEY) || "").trim();
  const savedUserRaw = String(localStorage.getItem(LEGACY_AUTH_USER_KEY) || "").trim();

  if (!savedToken || !savedUserRaw) {
    state.auth.token = "";
    state.auth.user = null;
    renderAuthState();
    return;
  }

  try {
    const savedUser = normalizeAuthUser(JSON.parse(savedUserRaw));

    if (savedUser) {
      state.auth.token = savedToken;
      state.auth.user = savedUser;
      syncProfileActivityFromAuthUser(savedUser);
      renderAuthState();
    }

    const payload = await fetchJson("/api/v1/auth/me", {
      headers: {
        Authorization: `Bearer ${savedToken}`
      }
    });

    saveAuth(savedToken, payload.user);
  } catch {
    clearAuth();
  }
}

async function loadInitialData() {
  const [aggregatesPayload, marketsPayload, exchangesPayload, exchangesStatusPayload] = await Promise.all([
    fetchJson("/api/v1/aggregates"),
    fetchJson("/api/v1/markets"),
    fetchJson("/api/v1/exchanges"),
    fetchJson("/api/v1/exchanges/status")
  ]);

  state.configuredExchanges = Array.isArray(exchangesPayload.data)
    ? exchangesPayload.data.map((item) => String(item || "").toLowerCase()).filter(Boolean)
    : [];

  state.tickStaleAfterMs = normalizeTickStaleAfterMs(
    aggregatesPayload.staleAfterMs ?? marketsPayload.staleAfterMs,
    state.tickStaleAfterMs
  );

  setExchangeHealthData(exchangesStatusPayload.data || []);

  for (const aggregateRaw of aggregatesPayload.data || []) {
    const aggregate = normalizeAggregateRecord(aggregateRaw);

    if (!aggregate) {
      continue;
    }

    state.aggregatesBySymbol.set(aggregate.symbol, aggregate);
    pushLivePoint(aggregate.symbol, Number(aggregate.midPrice), Number(aggregate.updatedAt));
  }

  for (const tick of marketsPayload.data || []) {
    const symbol = String(tick?.symbol || "").toUpperCase();
    const exchange = String(tick?.exchange || "").toLowerCase();

    if (!symbol || !exchange) {
      continue;
    }

    let perExchange = state.latestTickBySymbolExchange.get(symbol);

    if (!perExchange) {
      perExchange = new Map();
      state.latestTickBySymbolExchange.set(symbol, perExchange);
    }

    perExchange.set(exchange, tick);
  }

  if (!state.selectedSymbol && state.aggregatesBySymbol.size > 0) {
    const first = Array.from(state.aggregatesBySymbol.values()).sort(
      (a, b) => Number(b.midPrice ?? 0) - Number(a.midPrice ?? 0)
    )[0];

    state.selectedSymbol = first?.symbol || null;
  }

  if (!state.marketView.symbol && state.selectedSymbol) {
    state.marketView.symbol = state.selectedSymbol;
  }
}

async function refreshSelectedHistory() {
  if (!state.selectedSymbol) {
    return;
  }

  try {
    const body = await fetchJson(`/api/v1/history/${state.selectedSymbol}?limit=120`);
    state.historyBySymbol.set(state.selectedSymbol, body.data || []);
  } catch {
    state.historyBySymbol.set(state.selectedSymbol, []);
  }

  renderLeaders();
  renderDetails();
  renderMarketTab();
}

function markUiDirty(next) {
  Object.keys(state.uiDirty).forEach((key) => {
    if (next[key]) {
      state.uiDirty[key] = true;
    }
  });

  if (state.uiTimer) {
    return;
  }

  state.uiTimer = setTimeout(() => {
    state.uiTimer = null;
    const dirty = state.uiDirty;
    state.uiDirty = createUiDirty();

    if (dirty.summary) {
      renderSummary();
    }

    if (dirty.marketTable) {
      renderMarketTable();
    }

    if (dirty.leaders) {
      renderLeaders();
    }

    if (dirty.marketTab) {
      renderMarketTab();
    }

    if (dirty.details) {
      renderDetails();
    }

    if (dirty.exchanges) {
      renderExchangesTab();
    }
  }, UI_REFRESH_MS);
}

function isRealtimeUpdatePaused() {
  try {
    const guardState = window.__networkGuard?.getState?.();

    if (guardState?.active || guardState?.forcedOffline || guardState?.serverMarketOffline) {
      return true;
    }
  } catch {
    // keep live rendering available if the guard itself is unavailable
  }

  if (document.documentElement?.dataset?.networkGuardState === "offline") {
    return true;
  }

  if (document.body?.classList?.contains("network-offline")) {
    return true;
  }

  if (typeof navigator !== "undefined" && navigator.onLine === false) {
    return true;
  }

  return false;
}

function connectWs() {
  const protocol = window.location.protocol === "https:" ? "wss" : "ws";
  const token = String(state.auth.token || localStorage.getItem(LEGACY_AUTH_TOKEN_KEY) || "").trim();
  const wsUrl = token
    ? `${protocol}://${window.location.host}/ws?token=${encodeURIComponent(token)}`
    : `${protocol}://${window.location.host}/ws`;
  const ws = new WebSocket(wsUrl);
  state.ws.socket = ws;

  setWsState("connecting", false);

  ws.addEventListener("open", () => {
    setWsState("connected", true);

    if (state.auth.token) {
      ws.send(JSON.stringify({ type: "auth", token: state.auth.token }));
    }
  });

  ws.addEventListener("close", () => {
    if (state.ws.socket === ws) {
      state.ws.socket = null;
    }

    setWsState("disconnected", false);
    setTimeout(connectWs, 2000);
  });

  ws.addEventListener("error", () => {
    setWsState("error", false);
  });

  ws.addEventListener("message", (event) => {
    try {
      const msg = JSON.parse(event.data);

      if ((msg.type === "aggregate" || msg.type === "tick") && isRealtimeUpdatePaused()) {
        return;
      }

      if (msg.type === "aggregate" && msg.data?.symbol) {
        const aggregate = normalizeAggregateRecord(msg.data);

        if (!aggregate) {
          return;
        }

        state.tickStaleAfterMs = normalizeTickStaleAfterMs(aggregate.staleAfterMs, state.tickStaleAfterMs);
        state.aggregatesBySymbol.set(aggregate.symbol, aggregate);
        pushLivePoint(aggregate.symbol, Number(aggregate.midPrice), Number(aggregate.updatedAt));

        if (!state.selectedSymbol) {
          state.selectedSymbol = aggregate.symbol;
        }

        if (!state.marketView.symbol) {
          state.marketView.symbol = aggregate.symbol;
        }

        markUiDirty({
          summary: true,
          marketTable: true,
          leaders: true,
          marketTab: true,
          details: aggregate.symbol === state.selectedSymbol
        });
      }

      if (msg.type === "tick" && msg.data?.symbol && msg.data?.exchange) {
        let perExchange = state.latestTickBySymbolExchange.get(msg.data.symbol);

        if (!perExchange) {
          perExchange = new Map();
          state.latestTickBySymbolExchange.set(msg.data.symbol, perExchange);
        }

        perExchange.set(msg.data.exchange, msg.data);

        markUiDirty({
          summary: true,
          exchanges: true
        });
      }
    } catch {
      // ignore malformed frames
    }
  });
}

